export interface DailyPractice {
  id: number;
  type: number;
  category: "shadow" | "growth" | "mindfulness" | "relationship" | "affirmation";
  title: string;
  prompt: string;
  dayNumber: number;
}

export const dailyPractices: DailyPractice[] = [
  { id: 1, type: 1, category: "shadow", title: "The Inner Critic\'s Voice", prompt: "Spend five minutes writing down every critical thought you have about yourself today. When you read them back, notice: whose voice is this really? A parent, teacher, or authority figure? Recognize that this voice was internalized — it is not the voice of truth.", dayNumber: 1 },
  { id: 2, type: 1, category: "shadow", title: "The Resentment Inventory", prompt: "Ones often deny their anger by calling it \"frustration\" or \"disappointment.\" Today, journal honestly: who are you resentful toward right now, and what do you believe they *should* be doing differently? Notice how the word \"should\" feels in your body.", dayNumber: 2 },
  { id: 3, type: 1, category: "shadow", title: "Catching Black-and-White Thinking", prompt: "Today, when you notice yourself categorizing something as entirely right or entirely wrong, pause. Write down three ways the situation is more nuanced than your initial judgment. Practice holding the gray zone without resolving it.", dayNumber: 3 },
  { id: 4, type: 1, category: "shadow", title: "The Pleasure Prohibition", prompt: "Notice today if you feel guilty for enjoying something — a long break, a rich meal, an indulgent show. Ask yourself: \"What rule am I breaking by feeling pleasure right now?\" Journal about where that rule came from and whether you still choose to live by it.", dayNumber: 4 },
  { id: 5, type: 1, category: "shadow", title: "Your Secret Standards", prompt: "Write down five unspoken standards you hold others to that you have never explicitly communicated. For each one, ask: \"Is this truly a moral issue, or is this my preference disguised as a principle?\"", dayNumber: 5 },
  { id: 6, type: 1, category: "shadow", title: "The Body of Anger", prompt: "Ones often hold anger in their jaw, shoulders, and gut without recognizing it as anger. Three times today, scan your body for tension. When you find it, say internally: \"This might be anger. I am allowed to feel anger.\" Do not try to fix it — just acknowledge it.", dayNumber: 6 },
  { id: 7, type: 1, category: "shadow", title: "Perfection as Procrastination", prompt: "Identify one task you have been delaying because you cannot do it perfectly. Today, do it at 70% quality and submit it. Journal about the anxiety this produces and what catastrophe you feared would result from imperfection.", dayNumber: 7 },
  { id: 8, type: 1, category: "shadow", title: "The Moral Superiority Check", prompt: "Honestly examine: in the last week, when did you feel morally superior to someone? What triggered it? Underneath that superiority, what vulnerability were you protecting? Ones often use righteousness to avoid feeling flawed.", dayNumber: 8 },
  { id: 9, type: 1, category: "shadow", title: "Reclaiming the \"Lazy\" Self", prompt: "Ones reject the part of themselves that wants to rest, wander, or be unproductive. Today, deliberately do something \"lazy\" for 30 minutes with zero justification. Notice the inner voice that says you do not deserve this.", dayNumber: 9 },
  { id: 10, type: 1, category: "shadow", title: "The Forbidden Emotion", prompt: "Ones unconsciously believe anger is unacceptable, so it leaks out as irritability, sarcasm, or passive correction. Today, practice saying to yourself: \"I am angry about ___.\" Name it plainly. Notice how direct acknowledgment actually reduces the anger rather than amplifying it.", dayNumber: 10 },
  { id: 11, type: 1, category: "growth", title: "Spontaneous Detour", prompt: "At some point today, deviate from your plan. Take a different route, try a new restaurant, or say yes to an unexpected invitation. Afterward, reflect: did anything bad happen from abandoning your plan? What did you gain?", dayNumber: 11 },
  { id: 12, type: 1, category: "growth", title: "The Joy Audit", prompt: "Write down ten things that bring you genuine joy — not satisfaction from a job well done, but pure, childlike delight. When did you last do each one? Schedule one for this week with no productive purpose attached.", dayNumber: 12 },
  { id: 13, type: 1, category: "growth", title: "Play Without Purpose", prompt: "Spend 20 minutes doing something that has absolutely no productive value: doodle, build something silly, dance alone, or play a game. If the inner critic says \"this is a waste of time,\" thank it and continue playing.", dayNumber: 13 },
  { id: 14, type: 1, category: "growth", title: "Lighten Your Grip", prompt: "Choose one area where you have been tightly controlling an outcome — a project, a household routine, someone else\'s behavior. Today, consciously let go of managing it. Observe what happens when you release the reins.", dayNumber: 14 },
  { id: 15, type: 1, category: "growth", title: "The Reframe Practice", prompt: "When something goes wrong today, practice the Seven\'s gift: reframing. Instead of \"this is a problem,\" ask: \"What is interesting or funny about this situation?\" You are not denying the difficulty — you are expanding your response to include lightness.", dayNumber: 15 },
  { id: 16, type: 1, category: "growth", title: "Adventure Micro-Dose", prompt: "Ones can become rigid in their routines. Today, introduce one small element of adventure: a new podcast genre, a spice you have never cooked with, a conversation with a stranger. Let novelty remind you that growth happens outside structure.", dayNumber: 16 },
  { id: 17, type: 1, category: "growth", title: "Permission to Be Silly", prompt: "At your integration point, you access the Seven\'s capacity for uninhibited self-expression. Today, be deliberately silly with someone — tell a bad joke, make an exaggerated face, or do something undignified. Notice what it feels like to let your guard down.", dayNumber: 17 },
  { id: 18, type: 1, category: "growth", title: "The Good Enough Celebration", prompt: "Instead of focusing on what fell short today, write down three things that went well enough. Not perfectly — just enough. Practice the inner statement: \"This is good enough, and I can celebrate it.\"", dayNumber: 18 },
  { id: 19, type: 1, category: "growth", title: "Future Pleasure Planning", prompt: "Sevens are energized by anticipation. Borrow this gift: plan something purely delightful for the coming weeks — a trip, a gathering, a creative project. Let yourself feel excitement without immediately turning it into a to-do list with deadlines.", dayNumber: 19 },
  { id: 20, type: 1, category: "growth", title: "The \"Yes, And\" Day", prompt: "Borrowed from improv: today, when someone suggests something, practice saying \"yes, and...\" instead of pointing out flaws or proposing a better alternative. Let other people\'s ideas carry forward without your correction.", dayNumber: 20 },
  { id: 21, type: 1, category: "mindfulness", title: "Grounding Through the Soles", prompt: "As a gut-center type, your body holds deep wisdom but also deep tension. Stand barefoot for three minutes. Feel every point of contact between your feet and the ground. Breathe into your belly. Let the earth hold you — you do not have to hold everything.", dayNumber: 21 },
  { id: 22, type: 1, category: "mindfulness", title: "Anger as Energy", prompt: "When you notice irritation or tension today, pause and feel it purely as energy in your body — not as a story about who is wrong. Where does the energy live? What does it want to do? Let it move through you without directing it at anyone.", dayNumber: 22 },
  { id: 23, type: 1, category: "mindfulness", title: "The Three-Breath Reset", prompt: "Three times today, take three deliberate breaths before responding to any situation that triggers your inner critic. On the first breath, notice the judgment. On the second, feel your feet on the ground. On the third, choose your response rather than reacting.", dayNumber: 23 },
  { id: 24, type: 1, category: "mindfulness", title: "Belly Breathing for Serenity", prompt: "Your virtue is serenity, which lives in a relaxed gut center. Spend five minutes breathing deeply into your belly — not your chest. With each exhale, mentally repeat \"serenity.\" Notice how relaxing your abdomen changes the quality of your thoughts.", dayNumber: 24 },
  { id: 25, type: 1, category: "mindfulness", title: "The Tension Scan", prompt: "Ones hold chronic tension as a form of control. Set three alarms today. At each alarm, scan your jaw, shoulders, hands, and gut. Where are you bracing? Consciously soften those areas. You do not need to hold yourself together so tightly.", dayNumber: 25 },
  { id: 26, type: 1, category: "mindfulness", title: "Walking Without Correcting", prompt: "Take a 15-minute walk with one rule: do not mentally correct anything you see. Not the crooked sign, not the person jaywalking, not the poorly parked car. Simply observe the world as it is. This is a practice in the gut-center virtue of acceptance.", dayNumber: 26 },
  { id: 27, type: 1, category: "mindfulness", title: "The \"Just This\" Practice", prompt: "When you find yourself mentally improving, optimizing, or fixing something, say internally: \"Just this.\" The messy desk — just this. The imperfect conversation — just this. Practice meeting reality without the overlay of how it should be.", dayNumber: 27 },
  { id: 28, type: 1, category: "mindfulness", title: "Physical Release of Resentment", prompt: "Resentment accumulates in the One\'s body like sediment. Today, do a vigorous physical activity — run, scrub a floor, pound a pillow — and consciously assign the physical exertion to releasing a specific resentment. Feel it leaving your body through movement.", dayNumber: 28 },
  { id: 29, type: 1, category: "mindfulness", title: "The Exhale of Letting Go", prompt: "Throughout the day, practice extended exhales (breathe in for 4 counts, out for 8). With each long exhale, mentally release one thing you are trying to control. The exhale is the physiological signal of the parasympathetic nervous system — it teaches your body that it is safe to let go.", dayNumber: 29 },
  { id: 30, type: 1, category: "mindfulness", title: "Eating Without Judgment", prompt: "At one meal today, eat something you enjoy without mentally categorizing it as \"good\" or \"bad\" food. Taste it fully. Let pleasure exist without the chaperone of your inner nutritionist. Your gut center heals when it is allowed to receive nourishment without critique.", dayNumber: 30 },
  { id: 31, type: 1, category: "relationship", title: "The Criticism Fast", prompt: "For the next 24 hours, commit to zero unsolicited criticism or correction of anyone — partner, child, colleague, stranger. When the urge arises, write it down privately instead. At day\'s end, review the list: how many were truly necessary?", dayNumber: 31 },
  { id: 32, type: 1, category: "relationship", title: "Asking Instead of Telling", prompt: "Today, replace one directive statement with a genuine question. Instead of \"You should do it this way,\" try \"How are you thinking about approaching this?\" Notice how hard it is to trust others\' processes — and practice doing it anyway.", dayNumber: 32 },
  { id: 33, type: 1, category: "relationship", title: "Apologizing for Rigidity", prompt: "Think of one recent time your need to be right damaged a relationship. Today, approach that person and say something like: \"I think I was more focused on being correct than on understanding you. I am sorry.\" Notice how vulnerability feels compared to righteousness.", dayNumber: 33 },
  { id: 34, type: 1, category: "relationship", title: "Seeing Others\' Goodness", prompt: "Your fixation on judging makes you hyper-aware of others\' flaws. Today, for every person you interact with, silently name one thing that is genuinely good about them. Write these down. Practice the belief that people are doing their best.", dayNumber: 34 },
  { id: 35, type: 1, category: "relationship", title: "Receiving Without Improving", prompt: "When someone shares their work, their cooking, their idea, or their feelings with you today, receive it without suggesting improvements. Say: \"Thank you. I appreciate this.\" Full stop. The gift of your approval, unqualified, is more healing than your advice.", dayNumber: 35 },
  { id: 36, type: 1, category: "relationship", title: "The Repair Conversation", prompt: "Ones often express anger through cold withdrawal or clipped tones rather than direct conversation. Identify one person you have been subtly punishing with distance. Today, reconnect with warmth — not by discussing the issue, but by simply being kind.", dayNumber: 36 },
  { id: 37, type: 1, category: "relationship", title: "Admitting You Were Wrong", prompt: "Ones find this excruciating because their identity is built on being correct. Today, find one thing you were wrong about — even something small — and tell someone. Practice the sentence: \"I was wrong about that.\" Feel how the world does not end.", dayNumber: 37 },
  { id: 38, type: 1, category: "relationship", title: "Holding Space for Imperfection", prompt: "When someone in your life makes a mistake today, consciously choose compassion over correction. Remind yourself: \"This person is not a project for me to improve. They are a human being learning, just like me.\"", dayNumber: 38 },
  { id: 39, type: 1, category: "relationship", title: "The Unearned Warmth Practice", prompt: "Ones sometimes dispense warmth as a reward for good behavior. Today, be warm toward someone who has not \"earned\" it — someone who is messy, late, or doing things wrong. Practice unconditional positive regard as a spiritual discipline.", dayNumber: 39 },
  { id: 40, type: 1, category: "relationship", title: "Sharing Your Inner Struggle", prompt: "Ones project an image of having it all together. Today, share one genuine struggle with someone you trust — not a struggle you have already resolved, but one that is still alive. Let someone see you as imperfect and in process.", dayNumber: 40 },
  { id: 41, type: 1, category: "affirmation", title: "\"I am good — not because I am perfect, but because goodness is my nature.\"", prompt: "Repeat this when your inner critic equates your worth with your performance. Place your hand over your heart as you say it, grounding the truth in your body rather than your mind.", dayNumber: 41 },
  { id: 42, type: 1, category: "affirmation", title: "\"Serenity comes from acceptance, not from getting everything right.\"", prompt: "Use this when you feel the compulsive need to fix or improve something. Whisper it to yourself three times, letting each repetition soften your grip on the situation.", dayNumber: 42 },
  { id: 43, type: 1, category: "affirmation", title: "\"My anger is valid and welcome. It does not make me bad.\"", prompt: "Ones fear their own anger because they equate it with the corruption they despise. Today, when you feel angry, say this mantra internally. Anger is information, not indictment.", dayNumber: 43 },
  { id: 44, type: 1, category: "affirmation", title: "\"Done is better than perfect.\"", prompt: "Write this on a sticky note and place it where you work. Each time you see it, let it remind you that completion is its own form of integrity — and that perfectionism is not a virtue but a prison.", dayNumber: 44 },
  { id: 45, type: 1, category: "affirmation", title: "\"I release others from the burden of my expectations.\"", prompt: "Say this before interacting with someone you tend to judge or correct. Visualize literally lifting a weight off their shoulders. Notice how this changes the quality of the interaction.", dayNumber: 45 },
  { id: 46, type: 1, category: "affirmation", title: "\"The world does not need me to be its quality control department.\"", prompt: "Use this with humor and affection toward yourself when you catch yourself mentally editing the world. Smile at your inner reformer. It means well, but it needs a day off.", dayNumber: 46 },
  { id: 47, type: 1, category: "affirmation", title: "\"I can rest without earning it.\"", prompt: "Repeat this tonight before bed. Ones often feel they must justify rest with productivity. Tonight, let rest be an inherent right, not a reward. You are a human being, not a human doing.", dayNumber: 47 },
  { id: 48, type: 1, category: "affirmation", title: "\"Mistakes are not moral failures.\"", prompt: "When you make an error today, say this before the shame spiral begins. Errors are data, not character flaws. Let this mantra interrupt the One\'s automatic equation of mistake with moral deficit.", dayNumber: 48 },
  { id: 49, type: 1, category: "affirmation", title: "\"Joy is not frivolous — it is essential.\"", prompt: "Place this where you will see it first thing in the morning. Let it give you permission to seek delight today without requiring that it be productive, educational, or improving.", dayNumber: 49 },
  { id: 50, type: 1, category: "affirmation", title: "\"I choose compassion over correctness.\"", prompt: "Use this as a decision-making filter today. When you face a choice between being right and being kind, let this mantra tip the scale toward kindness. Notice how this changes your experience of the day.", dayNumber: 50 },
  { id: 51, type: 2, category: "shadow", title: "The Hidden Ledger", prompt: "Twos often keep an unconscious ledger of what they have given and what they are owed. Today, journal honestly: where do you feel someone owes you — gratitude, attention, reciprocation? What would it mean to cancel that debt entirely?", dayNumber: 1 },
  { id: 52, type: 2, category: "shadow", title: "Naming Your Own Needs", prompt: "Right now, write down five things you genuinely need — not what others need from you, but what you need for yourself. If this feels difficult or uncomfortable, notice that discomfort. Twos often cannot access their own needs because the habit of attending to others has buried them.", dayNumber: 2 },
  { id: 53, type: 2, category: "shadow", title: "The Helping Motive Inquiry", prompt: "Think of the last time you helped someone. Now ask honestly: what did you hope to receive in return? Acknowledgment? Closeness? A sense of being indispensable? There is no wrong answer — the practice is simply in seeing the full truth of your motivations.", dayNumber: 3 },
  { id: 54, type: 2, category: "shadow", title: "Manipulation Through Generosity", prompt: "This is the Two\'s most uncomfortable shadow: using helpfulness to control relationships. Journal about a time when your \"help\" was actually a strategy to make someone need you, depend on you, or feel obligated to you. Compassionately acknowledge this pattern.", dayNumber: 4 },
  { id: 55, type: 2, category: "shadow", title: "The Pride Beneath the Humility", prompt: "Twos carry a subtle pride: \"I am the one who gives. I am the one who knows what others need.\" Today, notice when this pride arises. What does it feel like to believe you understand someone else\'s needs better than they do? Where might you be wrong?", dayNumber: 5 },
  { id: 56, type: 2, category: "shadow", title: "The Exhaustion Inventory", prompt: "If you are chronically exhausted, it may be because you are over-giving. List everything you did for others this week. Now circle the items that were genuinely asked for versus the ones you volunteered. What would your week look like if you only did what was requested?", dayNumber: 6 },
  { id: 57, type: 2, category: "shadow", title: "Sitting With Rejection", prompt: "Twos work desperately to avoid rejection by making themselves indispensable. Today, journal about your deepest fear of rejection. What do you believe would happen if someone simply did not need you? Who are you if you are not the helper?", dayNumber: 7 },
  { id: 58, type: 2, category: "shadow", title: "Feeling Anger at Ingratitude", prompt: "Twos often deny their anger, but it surfaces as hurt when their giving is not reciprocated. Today, allow yourself to feel angry — genuinely, openly angry — about a time someone took your help for granted. Your anger is information about a boundary you need.", dayNumber: 8 },
  { id: 59, type: 2, category: "shadow", title: "The Flattery Mirror", prompt: "Your fixation is flattery — intuitively knowing what others want to hear and providing it. Today, catch yourself adapting your personality or words to please someone. Ask: \"What would I say if I were not trying to be liked right now?\"", dayNumber: 9 },
  { id: 60, type: 2, category: "shadow", title: "Who Am I Without You?", prompt: "Twos can lose themselves in relationships. Spend 15 minutes journaling about who you are outside of your roles as helper, partner, parent, or friend. What do you like? What do you believe? What do you want? If these questions feel foreign, that itself is the insight.", dayNumber: 10 },
  { id: 61, type: 2, category: "growth", title: "Sacred Solitude", prompt: "At your integration point, you access the Four\'s capacity for rich inner life. Today, spend 30 minutes completely alone — no phone, no service to others, no caretaking. Sit with yourself. Journal, make art, or simply feel your feelings without directing them toward anyone.", dayNumber: 11 },
  { id: 62, type: 2, category: "growth", title: "Emotional Honesty Practice", prompt: "Fours are masters of emotional authenticity. Today, practice telling someone how you really feel — not the polished, pleasant version, but the raw truth. \"I feel hurt.\" \"I feel overlooked.\" \"I need space.\" Let your real emotions be visible.", dayNumber: 12 },
  { id: 63, type: 2, category: "growth", title: "Creating Something for Yourself", prompt: "Do something creative today that is entirely for you — write a poem, paint, rearrange a room, cook an elaborate meal for one. The Four\'s gift is self-expression. Let yourself create without it being a gift for someone else.", dayNumber: 13 },
  { id: 64, type: 2, category: "growth", title: "The Depth Dive", prompt: "Instead of skimming the surface of your emotions today (as Twos often do by redirecting attention to others), go deep into one feeling. Sit with sadness, longing, or grief for fifteen minutes. Do not fix it. Do not offer it to anyone. Simply feel it fully.", dayNumber: 14 },
  { id: 65, type: 2, category: "growth", title: "Claiming Your Aesthetic", prompt: "Fours have a strong sense of personal identity expressed through aesthetics. Today, wear something, listen to something, or surround yourself with something that reflects your authentic taste — not what you think others will approve of, but what genuinely moves you.", dayNumber: 15 },
  { id: 66, type: 2, category: "growth", title: "The Unavailability Practice", prompt: "Today, make yourself deliberately unavailable for two hours. Turn off your phone, close your door, decline requests. This is not selfishness — it is the Four\'s understanding that withdrawing to connect with yourself is as essential as connecting with others.", dayNumber: 16 },
  { id: 67, type: 2, category: "growth", title: "Writing Your Story", prompt: "Fours are meaning-makers. Today, journal about a painful experience from your past. But instead of focusing on how you helped others through it, write about how it affected you — your private suffering, your personal growth, your unwitnessed resilience.", dayNumber: 17 },
  { id: 68, type: 2, category: "growth", title: "Receiving Without Reciprocating", prompt: "When someone offers you something today — a compliment, a favor, a gift — receive it without immediately giving something back. Say \"thank you\" and stop. Feel the discomfort of being on the receiving end. This is your growth edge.", dayNumber: 18 },
  { id: 69, type: 2, category: "growth", title: "The Identity Reclamation", prompt: "Write a list of things you once loved before you became absorbed in caretaking. A hobby, a genre of music, a dream. Choose one and re-engage with it this week. The Four integration invites you to remember who you are apart from your relationships.", dayNumber: 19 },
  { id: 70, type: 2, category: "growth", title: "Melancholy as Medicine", prompt: "Twos avoid sadness by staying busy with others. Today, let yourself feel melancholy without fixing it. Listen to a sad song, watch a poignant film, sit with the bittersweetness of life. The Four knows that sadness, fully felt, opens the door to depth.", dayNumber: 20 },
  { id: 71, type: 2, category: "mindfulness", title: "The Heart Check-In", prompt: "As a heart-center type, your emotional intelligence is your superpower — but also your blind spot when you direct it entirely outward. Set three alarms today. At each one, place your hand on your heart and ask: \"What am I feeling right now — for myself, about myself?\"", dayNumber: 21 },
  { id: 72, type: 2, category: "mindfulness", title: "The Chest Release", prompt: "Twos carry tension in their chest and arms — the body\'s posture of reaching out. Today, lie down with your arms at your sides, palms up. Breathe into your chest. With each exhale, practice the sensation of not reaching for anyone. Let your arms rest.", dayNumber: 22 },
  { id: 73, type: 2, category: "mindfulness", title: "Authentic Smile vs. Performance Smile", prompt: "Three times today, check in with your face. Are you smiling genuinely, or are you wearing a smile to manage someone else\'s comfort? Let your face relax into its natural expression, even if that expression is neutral or tired.", dayNumber: 23 },
  { id: 74, type: 2, category: "mindfulness", title: "Self-Compassion Touch", prompt: "When you notice yourself pouring energy outward, pause and offer yourself physical compassion. Wrap your arms around yourself, hold your own hand, or stroke your own hair. Give to yourself the tenderness you so readily give to others. Mean it.", dayNumber: 24 },
  { id: 75, type: 2, category: "mindfulness", title: "The Giving Pause", prompt: "Before each act of service today, pause for one full breath. In that pause, ask: \"Am I doing this from genuine generosity, or from a need to be needed?\" There is no wrong answer — but the pause itself interrupts the automatic pattern and creates choice.", dayNumber: 25 },
  { id: 76, type: 2, category: "mindfulness", title: "Embodied Self-Worth", prompt: "Stand in front of a mirror. Look at yourself — not with assessment, but with the same warmth you would offer a beloved friend. Place your hand on your heart and say: \"I am worthy of love simply because I exist, not because of what I give.\"", dayNumber: 26 },
  { id: 77, type: 2, category: "mindfulness", title: "The Boundary Meditation", prompt: "Close your eyes and visualize a gentle, warm boundary — like a circle of light — around your body. This boundary allows love in and out, but it defines where you end and others begin. Spend five minutes breathing inside this boundary, feeling its protection.", dayNumber: 27 },
  { id: 78, type: 2, category: "mindfulness", title: "Tears for Yourself", prompt: "Twos often cry for others but rarely for themselves. Today, if you can, let yourself cry about your own pain — not someone else\'s. If tears do not come, journal about what you would cry about if you allowed yourself to. Your pain deserves the same tenderness you give everyone else.", dayNumber: 28 },
  { id: 79, type: 2, category: "mindfulness", title: "The Empty Hands Practice", prompt: "Sit for five minutes with your hands open, palms up, holding nothing. Resist the urge to reach for your phone, a task, or someone else\'s problem. Practice the feeling of simply being — hands empty, heart full, no one to save.", dayNumber: 29 },
  { id: 80, type: 2, category: "mindfulness", title: "Nourishing Yourself First", prompt: "Today, at one meal, serve yourself first. Not out of selfishness, but as a practice in the radical act of meeting your own needs before attending to others. Notice any guilt and name it: \"This is my conditioning, not my truth.\"", dayNumber: 30 },
  { id: 81, type: 2, category: "relationship", title: "Saying No With Love", prompt: "Today, say no to one request — not with guilt or elaborate explanation, but with simple warmth: \"I cannot do that today, but I wish you well with it.\" Notice that the relationship survives your no. In fact, it may deepen with your honesty.", dayNumber: 31 },
  { id: 82, type: 2, category: "relationship", title: "Asking for Help", prompt: "Twos give but rarely ask. Today, ask someone for specific help with something you need — not a test to see if they will offer, but a direct, vulnerable request. \"Could you help me with ___?\" Feel the discomfort of being the one who needs.", dayNumber: 32 },
  { id: 83, type: 2, category: "relationship", title: "Releasing the Savior Role", prompt: "Identify one person you have been trying to rescue, fix, or improve. Today, consciously step back. Remind yourself: \"This person has their own wisdom, their own path, and their own timing. My job is to love them, not to save them.\"", dayNumber: 33 },
  { id: 84, type: 2, category: "relationship", title: "The Honest Compliment", prompt: "Twos are masters of strategic flattery. Today, give only compliments you genuinely mean — and if you cannot think of an honest one, stay silent. Practice the integrity of authentic praise rather than the currency of approval.", dayNumber: 34 },
  { id: 85, type: 2, category: "relationship", title: "Telling Someone What You Need", prompt: "Choose one important relationship and tell that person something you need that you have not been expressing. \"I need more quality time.\" \"I need to feel appreciated.\" \"I need space.\" Specificity is an act of trust and courage for a Two.", dayNumber: 35 },
  { id: 86, type: 2, category: "relationship", title: "Allowing Someone to Struggle", prompt: "When someone you love is struggling today, resist the urge to intervene. Sit with them in their difficulty without fixing it. Say: \"That sounds really hard. I am here.\" Sometimes presence, not problem-solving, is the deepest form of love.", dayNumber: 36 },
  { id: 87, type: 2, category: "relationship", title: "Checking Your Shape-Shifting", prompt: "Notice today if you present a different version of yourself to different people. Are you accommodating, funny, nurturing, or serious depending on who you are with? Journal about which version feels most like the real you.", dayNumber: 37 },
  { id: 88, type: 2, category: "relationship", title: "Equal Conversations", prompt: "In your next meaningful conversation, track the balance. Are you asking about them and deflecting questions about yourself? Today, match every question you ask with something you share about your own experience. Let the conversation be genuinely mutual.", dayNumber: 38 },
  { id: 89, type: 2, category: "relationship", title: "The Love Without Doing Practice", prompt: "Choose one person you love and, today, express that love without doing anything for them. No favors, no gifts, no acts of service. Simply be present, attentive, and warm. Let your love exist independent of your usefulness.", dayNumber: 39 },
  { id: 90, type: 2, category: "relationship", title: "Allowing Yourself to Be Known", prompt: "Twos often know everything about others while remaining unknowable themselves. Today, share something personal and unpolished — a fear, a dream, an embarrassment — with someone you trust. Let them see behind the helper\'s mask.", dayNumber: 40 },
  { id: 91, type: 2, category: "affirmation", title: "\"My needs are not a burden — they are sacred.\"", prompt: "Repeat this when you catch yourself minimizing what you need. Your needs are not inconveniences to be managed; they are signals from your deepest self. Place your hands on your belly and let this truth settle.", dayNumber: 41 },
  { id: 92, type: 2, category: "affirmation", title: "\"I am loved for who I am, not for what I do.\"", prompt: "This is the Two\'s core healing. Say it when you feel the compulsive pull to earn love through service. You do not need to perform to deserve connection. Your being is enough.", dayNumber: 42 },
  { id: 93, type: 2, category: "affirmation", title: "\"It is safe to receive.\"", prompt: "Use this when someone offers you kindness, a gift, or help. Twos deflect receiving because it feels vulnerable. Today, let this mantra soften your defenses. Open your hands and let good things flow toward you.", dayNumber: 43 },
  { id: 94, type: 2, category: "affirmation", title: "\"Not my circus, not my monkeys.\"", prompt: "Say this with gentle humor when you feel pulled into someone else\'s problem. Your compassion is a gift, but it does not obligate you to carry everyone\'s pain. You can love someone without managing their life.", dayNumber: 44 },
  { id: 95, type: 2, category: "affirmation", title: "\"My worth is inherent, not earned.\"", prompt: "When you feel the urge to prove your value through helping, repeat this. You were worthy of love before you ever did anything for anyone. This is the truth that pride obscures.", dayNumber: 45 },
  { id: 96, type: 2, category: "affirmation", title: "\"I choose to give from overflow, not from depletion.\"", prompt: "Use this as a daily check before committing to help someone. If your cup is empty, filling others\' cups drains you further. Generosity is sustainable only when it flows from abundance.", dayNumber: 46 },
  { id: 97, type: 2, category: "affirmation", title: "\"I am allowed to put myself first.\"", prompt: "This will feel selfish. Say it anyway. The discomfort you feel is not evidence that you are being selfish — it is evidence of how deeply you have been conditioned to abandon yourself. First is not only; it is a starting place.", dayNumber: 47 },
  { id: 98, type: 2, category: "affirmation", title: "\"Saying no is a complete sentence.\"", prompt: "Practice this when you feel the need to justify, explain, or soften your boundaries with elaborate reasons. \"No\" is not a rejection of the other person — it is an embrace of yourself.", dayNumber: 48 },
  { id: 99, type: 2, category: "affirmation", title: "\"I release the need to be needed.\"", prompt: "This mantra confronts the Two\'s deepest identity structure. Who are you without someone to help? You are a whole person with your own inner landscape. Let this mantra crack open the question with curiosity rather than fear.", dayNumber: 49 },
  { id: 100, type: 2, category: "affirmation", title: "\"I am the love I have been seeking.\"", prompt: "Use this as a closing meditation. The love you pour into others often compensates for a love you believe you lack. But the source of love is within you. You have always been the thing you were searching for.", dayNumber: 50 },
  { id: 101, type: 3, category: "shadow", title: "The Image Audit", prompt: "Today, notice every time you adjust your behavior, words, or appearance to manage how someone perceives you. Count the instances. At day\'s end, journal: which version of you is the real one? What would happen if someone saw the unpolished version?", dayNumber: 1 },
  { id: 102, type: 3, category: "shadow", title: "Feelings Beneath the Doing", prompt: "Threes stay in motion to avoid feeling. Right now, stop. Sit still for ten minutes with no phone, no task, no plan. What emotions surface when there is nothing to achieve? Name them without judging or fixing them. This is the territory you have been avoiding.", dayNumber: 2 },
  { id: 103, type: 3, category: "shadow", title: "The Failure Meditation", prompt: "Recall your most painful failure. Not the one you have reframed as a learning experience, but the one that still stings. Sit with the raw shame of it. What did it threaten about your identity? What did you believe it proved about your worth?", dayNumber: 3 },
  { id: 104, type: 3, category: "shadow", title: "Workaholism as Anesthesia", prompt: "How many hours did you work this week? Now ask: how many of those hours were truly necessary, and how many were a way to avoid something — loneliness, conflict, emptiness, intimacy? Journal about what your work protects you from feeling.", dayNumber: 4 },
  { id: 105, type: 3, category: "shadow", title: "Who Am I Without My Resume?", prompt: "Strip away your accomplishments, titles, and accolades. Write a description of yourself that mentions none of them. What remains? If this feels like nothing, that is the wound you are being invited to heal — the belief that you are your achievements.", dayNumber: 5 },
  { id: 106, type: 3, category: "shadow", title: "The Deception Inventory", prompt: "Your passion is deceit — not necessarily lying to others, but lying to yourself about who you are. Today, identify one way you are deceiving yourself. Perhaps about how happy you are, how successful a relationship is, or how fine you are with a situation.", dayNumber: 6 },
  { id: 107, type: 3, category: "shadow", title: "Competing With Ghosts", prompt: "Notice today when you mentally compare yourself to others — their success, their appearance, their life. Who are you competing with? Why? What prize are you trying to win? Threes often compete without realizing the race they are running was never real.", dayNumber: 7 },
  { id: 108, type: 3, category: "shadow", title: "The Efficiency Trap", prompt: "Threes optimize everything — even relationships and emotions. Today, do something deliberately inefficiently. Take the long way. Have a conversation with no agenda. Let time pass without extracting value from it. Notice how this feels.", dayNumber: 8 },
  { id: 109, type: 3, category: "shadow", title: "Your Authentic Emotion", prompt: "When someone asks how you are today, do not answer with \"busy\" or \"great.\" Pause and check in with yourself for the real answer. You might be tired, anxious, sad, or confused. Practice reporting your actual emotional state rather than your brand.", dayNumber: 9 },
  { id: 110, type: 3, category: "shadow", title: "The Vanity Mirror", prompt: "Your fixation is vanity — not necessarily about physical appearance, but about being seen as successful, competent, and admirable. Journal about what would happen if the people you most want to impress saw you as ordinary. What fear lives underneath that scenario?", dayNumber: 10 },
  { id: 111, type: 3, category: "growth", title: "The Loyalty Practice", prompt: "At your integration point, you access the Six\'s gift of loyalty and commitment that is not contingent on success. Today, show up for someone or something not because it advances your goals, but simply because you said you would. Let faithfulness replace ambition.", dayNumber: 11 },
  { id: 112, type: 3, category: "growth", title: "Admitting Uncertainty", prompt: "Threes project confidence even when they are uncertain. Today, practice saying \"I do not know\" in a professional or social setting. Notice the vulnerability of not having the answer. The Six integration teaches that admitting uncertainty builds more trust than performing certainty.", dayNumber: 12 },
  { id: 113, type: 3, category: "growth", title: "Slowing Down to Connect", prompt: "Sixes value deep, reliable connection over impressive performance. Today, slow down a conversation. Instead of networking or impressing, ask genuine follow-up questions. Be curious about someone\'s inner life rather than their outer achievements.", dayNumber: 13 },
  { id: 114, type: 3, category: "growth", title: "The Vulnerability Share", prompt: "Tell someone about something that is not going well in your life — without spinning it into a comeback story. Let it sit as an unresolved struggle. The Six\'s gift is the courage to be vulnerable, which creates real intimacy rather than admiration.", dayNumber: 14 },
  { id: 115, type: 3, category: "growth", title: "Questioning Your Ambition", prompt: "The healthy Six questions motives and examines loyalty. Today, question one of your goals: \"Why do I really want this? Is this my genuine desire, or am I chasing validation? Who am I trying to prove myself to?\"", dayNumber: 15 },
  { id: 116, type: 3, category: "growth", title: "Following Instead of Leading", prompt: "Today, let someone else lead — a project, a decision, a plan. Support their vision without taking over or subtly redirecting. The Six integration helps Threes discover that following can be as meaningful as leading.", dayNumber: 16 },
  { id: 117, type: 3, category: "growth", title: "The Anti-Highlight Reel", prompt: "Instead of posting or sharing your best moments today, sit with an ordinary moment. A quiet meal. A boring commute. Let unremarkable time pass without curating it. The Six\'s gift is finding security in the ordinary rather than the exceptional.", dayNumber: 17 },
  { id: 118, type: 3, category: "growth", title: "Commitment Over Achievement", prompt: "Choose one commitment today that does not produce visible results — keeping a promise, maintaining a routine, supporting a friend\'s long-term process. Let the invisible, steady work of loyalty be its own reward.", dayNumber: 18 },
  { id: 119, type: 3, category: "growth", title: "Asking \"What If I Fail?\"", prompt: "Sixes are skilled at worst-case thinking, which Threes avoid. Today, honestly contemplate: what if your current project fails? What if you do not get the promotion? Sit with the scenario. You may find that the worst case is survivable — and that fearing it has been costing you more than facing it.", dayNumber: 19 },
  { id: 120, type: 3, category: "growth", title: "Team Over Star", prompt: "Today, actively elevate someone else\'s contribution. In a meeting, a conversation, or a project, shine the light on another person\'s work rather than positioning yourself at the center. Practice the Six\'s understanding that collective success is more sustainable than individual stardom.", dayNumber: 20 },
  { id: 121, type: 3, category: "mindfulness", title: "The Authenticity Body Scan", prompt: "Heart-center types carry the tension of image management in their chest and face. Lie down and scan from head to toe. Where are you performing? A held smile, a puffed chest, a sucked-in stomach? Consciously release each area and let your body take its natural, unimpressive shape.", dayNumber: 21 },
  { id: 122, type: 3, category: "mindfulness", title: "Heart-Rate Awareness", prompt: "Three times today, place your hand on your chest and feel your heartbeat. Not as a fitness metric, but as a reminder that you are a living being, not a productivity machine. Let each beat say: \"I am here. I am alive. That is enough.\"", dayNumber: 22 },
  { id: 123, type: 3, category: "mindfulness", title: "The Emotional Traffic Light", prompt: "Threes blow through yellow and red emotional signals. Today, practice a traffic light check: Green (I feel good), Yellow (something is off), Red (I need to stop). Set hourly reminders. When you hit yellow or red, pause and investigate before pushing through.", dayNumber: 23 },
  { id: 124, type: 3, category: "mindfulness", title: "Mirror Without Judgment", prompt: "Stand before a mirror for three minutes. Do not assess, critique, or admire. Do not adjust your hair or clothing. Simply look at the human being in front of you with neutral compassion. See yourself as you are, not as your brand.", dayNumber: 24 },
  { id: 125, type: 3, category: "mindfulness", title: "The Pause Between Tasks", prompt: "Threes move seamlessly from one task to the next without transition. Today, between each task, pause for sixty seconds. Close your eyes. Take three breaths. Ask: \"What just happened inside me?\" This creates space for emotions that speed buries.", dayNumber: 25 },
  { id: 126, type: 3, category: "mindfulness", title: "Walking Without a Destination", prompt: "Take a 20-minute walk with no fitness goal, no podcast, no step count. Walk slowly. Notice the world. Let walking be an act of being rather than doing. If your mind races toward your to-do list, gently return to the sensation of your feet on the ground.", dayNumber: 26 },
  { id: 127, type: 3, category: "mindfulness", title: "Self-Compassion for the Performer", prompt: "Place one hand on your heart and one on your belly. Say quietly: \"I know you are tired of performing. You can rest now. I love you regardless of what you accomplish today.\" Let these words sink past the achiever\'s armor.", dayNumber: 27 },
  { id: 128, type: 3, category: "mindfulness", title: "The Breath of Being", prompt: "Spend five minutes simply breathing. Not breathwork for optimization — just breathing. With each inhale, silently say \"I am.\" With each exhale, say \"enough.\" This is the antidote to the Three\'s core belief that they must constantly prove their value.", dayNumber: 28 },
  { id: 129, type: 3, category: "mindfulness", title: "Emotion Journaling", prompt: "At day\'s end, write down five emotions you felt today. Not \"productive\" or \"busy\" — those are states, not feelings. Dig deeper: anxious, proud, lonely, relieved, ashamed. Threes often have a limited emotional vocabulary because feelings slow them down. Expand yours.", dayNumber: 29 },
  { id: 130, type: 3, category: "mindfulness", title: "The Stillness Challenge", prompt: "Sit in stillness for ten minutes. No guided meditation, no app, no technique. Just you, alone with yourself. Notice what arises when there is nothing to achieve, no one to impress, and no outcome to optimize. This is where your authentic self waits.", dayNumber: 30 },
  { id: 131, type: 3, category: "relationship", title: "Dropping the Impressive Story", prompt: "In your next conversation, resist telling any story that positions you in a favorable light. Instead, share something mundane or self-deprecating. Notice how this changes the quality of the connection — it may deepen in ways that impressing never could.", dayNumber: 31 },
  { id: 132, type: 3, category: "relationship", title: "Presence Over Performance", prompt: "Choose one relationship interaction today where you are fully present — not scanning the room, not thinking about your next point, not curating your image. Give the person in front of you your complete, unproductive attention.", dayNumber: 32 },
  { id: 133, type: 3, category: "relationship", title: "Apologizing Without Explaining", prompt: "Threes turn apologies into explanations that protect their image. Today, if you owe someone an apology, offer it cleanly: \"I am sorry. I was wrong.\" Full stop. No context, no justification, no spinning it into a growth narrative.", dayNumber: 33 },
  { id: 134, type: 3, category: "relationship", title: "Letting Someone See You Struggle", prompt: "Threes show the world their wins and hide their struggles. Today, let one person see you in a moment of difficulty — not after you have resolved it, but while you are still in it. This is the foundation of intimacy.", dayNumber: 34 },
  { id: 135, type: 3, category: "relationship", title: "Quality Time Without Multitasking", prompt: "Give someone you love 30 minutes of completely undivided attention. No phone. No mental to-do list. No agenda. Just listen, be curious, and be present. For a Three, undivided attention is one of the most generous gifts possible.", dayNumber: 35 },
  { id: 136, type: 3, category: "relationship", title: "The Real Answer", prompt: "When someone asks how you are, today give the real answer. Not \"crushing it\" or \"so busy\" but the truth: \"I am actually feeling a bit lost\" or \"I am more tired than I want to admit.\" Let honesty replace branding in your closest relationships.", dayNumber: 36 },
  { id: 137, type: 3, category: "relationship", title: "Supporting Without Advising", prompt: "When someone shares a problem today, resist the urge to immediately solve it or share a similar-but-better story. Simply say: \"That makes sense. Tell me more.\" Let the conversation be about them, not about your competence.", dayNumber: 37 },
  { id: 138, type: 3, category: "relationship", title: "Being Known vs. Being Admired", prompt: "Journal about this question: would you rather be deeply known by a few people or widely admired by many? If the answer is admired, explore what being known threatens. Threes often fear that if people truly knew them, the admiration would vanish.", dayNumber: 38 },
  { id: 139, type: 3, category: "relationship", title: "Celebrating Others Without Comparison", prompt: "When someone you know achieves something today, celebrate them without any internal comparison. No \"I could do that too\" or \"they had advantages I did not.\" Pure, uncontaminated joy for their success. Notice how this feels.", dayNumber: 39 },
  { id: 140, type: 3, category: "relationship", title: "The Unplugged Date", prompt: "Spend an evening with someone you care about with all devices off. No photos for social media, no checking messages, no work emails. Let the evening be ephemeral and unrecorded. Practice the radical act of an unbroadcast life.", dayNumber: 40 },
  { id: 141, type: 3, category: "affirmation", title: "\"I am valuable simply because I exist, not because of what I produce.\"", prompt: "Repeat this when you feel the drive to earn your worth through achievement. Place both hands on your chest and breathe deeply. Your value is intrinsic and was never contingent on output.", dayNumber: 41 },
  { id: 142, type: 3, category: "affirmation", title: "\"It is safe to be seen as ordinary.\"", prompt: "This is the Three\'s most confronting mantra. Say it when you feel the compulsion to stand out or impress. Ordinary does not mean worthless — it means human, relatable, and real.", dayNumber: 42 },
  { id: 143, type: 3, category: "affirmation", title: "\"My feelings are not obstacles to my goals — they are my life.\"", prompt: "Use this when you catch yourself treating emotions as inefficiencies to be managed. Your feelings are not in the way of your life; they are your life. Let them slow you down today.", dayNumber: 43 },
  { id: 144, type: 3, category: "affirmation", title: "\"I can stop, and I will still be loved.\"", prompt: "Repeat this before bed, especially on nights when you feel you did not accomplish enough. The people who truly love you do not love your productivity. They love you. And \"you\" exists whether you are achieving or resting.", dayNumber: 44 },
  { id: 145, type: 3, category: "affirmation", title: "\"Failure does not diminish me.\"", prompt: "When you face a setback, say this before the spin machine activates. You do not need to reframe the failure as a win. You can simply let it be a failure — and still be whole.", dayNumber: 45 },
  { id: 146, type: 3, category: "affirmation", title: "\"The truth of who I am is better than any image I could craft.\"", prompt: "Your virtue is truthfulness. This mantra invites you to trust that your authentic self — messy, uncertain, imperfect — is more compelling than any polished persona you could create.", dayNumber: 46 },
  { id: 147, type: 3, category: "affirmation", title: "\"I do not need to win this moment.\"", prompt: "Use this in conversations, meetings, or social situations where you feel competitive. Not everything is a contest. Some moments just need your presence, not your victory.", dayNumber: 47 },
  { id: 148, type: 3, category: "affirmation", title: "\"Slowing down is not falling behind.\"", prompt: "When anxiety about pace grips you, repeat this. The race you are running has no finish line. Slowing down is how you find yourself — the self that speed keeps you running from.", dayNumber: 48 },
  { id: 149, type: 3, category: "affirmation", title: "\"I am more than my highlight reel.\"", prompt: "When you feel the urge to curate your life for external consumption, pause and say this. The full, uncurated version of your life — including the boring, the painful, and the uncertain — is worthy of being lived without an audience.", dayNumber: 49 },
  { id: 150, type: 3, category: "affirmation", title: "\"I choose connection over achievement today.\"", prompt: "Use this as a morning intention. It does not mean abandoning your goals — it means remembering that no accomplishment will ever satisfy the hunger that only genuine human connection can feed.", dayNumber: 50 },
  { id: 151, type: 4, category: "shadow", title: "The Envy Journal", prompt: "Today, write down every instance of envy you notice — social media scrolling, conversations, observations. For each one, name specifically what you envy. Then ask: \"What does this envy reveal about what I believe I lack?\" Envy is a map to your unmet desires.", dayNumber: 1 },
  { id: 152, type: 4, category: "shadow", title: "Ordinary and Complete", prompt: "Fours often believe they are fundamentally different from others in a way that means something is missing in them. Today, journal about this: what if nothing is missing? What if the sense of deficiency is a feeling, not a fact? Sit with the possibility that you are already complete.", dayNumber: 2 },
  { id: 153, type: 4, category: "shadow", title: "The Victimhood Inventory", prompt: "Honestly examine: where in your life do you cast yourself as the victim of circumstances, other people, or fate? Write down three situations where you have power you are not exercising because the victim role feels more emotionally familiar.", dayNumber: 3 },
  { id: 154, type: 4, category: "shadow", title: "Romanticizing Suffering", prompt: "Fours can unconsciously maintain suffering because it feels meaningful, deep, or authentically theirs. Today, identify one painful pattern you might be preserving because letting it go feels like losing part of your identity. What would you be without this wound?", dayNumber: 4 },
  { id: 155, type: 4, category: "shadow", title: "The Self-Absorption Mirror", prompt: "When you are lost in your emotional inner world, you can become blind to others\' experiences. Today, spend a conversation listening deeply to someone else\'s pain without comparing it to your own, redirecting to your experience, or internally ranking whose suffering is greater.", dayNumber: 5 },
  { id: 156, type: 4, category: "shadow", title: "The Specialness Trap", prompt: "Fours can use their sense of being unique as both a source of pride and a barrier to connection. Today, notice when you internally assert \"no one understands me\" or \"my experience is different.\" Ask: is this protecting me from the vulnerability of being understood?", dayNumber: 6 },
  { id: 157, type: 4, category: "shadow", title: "Push-Pull Awareness", prompt: "Fours often push people away when they get close, then pine for them when they leave. Today, notice any push-pull dynamics in your relationships. When you feel the urge to withdraw from someone who is offering closeness, pause and name what you are actually afraid of.", dayNumber: 7 },
  { id: 158, type: 4, category: "shadow", title: "The Fantasy vs. Reality Gap", prompt: "Journal about the gap between your ideal life and your actual life. Where are you so focused on what is missing that you cannot see what is present? Choose one thing in your real, current life that is genuinely good — and let yourself feel gratitude without the asterisk of longing.", dayNumber: 8 },
  { id: 159, type: 4, category: "shadow", title: "Emotional Indulgence Check", prompt: "There is a difference between feeling your feelings and wallowing in them. Today, when a strong emotion arises, set a timer for fifteen minutes. Feel it fully during that time. When the timer sounds, consciously choose to re-engage with the external world. Practice the art of feeling deeply without drowning.", dayNumber: 9 },
  { id: 160, type: 4, category: "shadow", title: "The Comparison Detox", prompt: "Fours compare constantly — not to feel superior, but to confirm their sense of lacking. Today, when you catch yourself comparing, say internally: \"I am comparing. This is my pattern, not reality.\" Then redirect your attention to something in your present moment that needs nothing added.", dayNumber: 10 },
  { id: 161, type: 4, category: "growth", title: "The Discipline of Action", prompt: "At your integration point, you access the One\'s gift of disciplined, principled action. Today, choose one task you have been avoiding because you are not \"in the mood\" and do it anyway. Let action precede inspiration rather than waiting for the perfect emotional state.", dayNumber: 11 },
  { id: 162, type: 4, category: "growth", title: "Structure as Freedom", prompt: "Fours resist structure because it feels constraining. But the One\'s structure actually creates freedom. Today, create a simple routine for your morning or evening. Follow it without deviation. Notice how structure can be a container for creativity rather than a cage.", dayNumber: 12 },
  { id: 163, type: 4, category: "growth", title: "Objectivity Practice", prompt: "When a strong emotional reaction arises today, practice stepping outside it. Ask: \"What would someone objective notice about this situation?\" Write down both the emotional truth and the factual truth side by side. Both are real — but the One integration adds balance.", dayNumber: 13 },
  { id: 164, type: 4, category: "growth", title: "Completing What You Start", prompt: "Fours start many creative projects and abandon them when the initial inspiration fades. Today, return to one unfinished project and work on it for thirty minutes — not because you feel inspired, but because completion is its own form of self-respect.", dayNumber: 14 },
  { id: 165, type: 4, category: "growth", title: "The \"Good Enough\" Standard", prompt: "Fours can be paralyzed by the gap between their artistic vision and their actual output. Today, borrow the One\'s pragmatism: produce something and declare it good enough. Release it. The world needs your work more than it needs your perfection.", dayNumber: 15 },
  { id: 166, type: 4, category: "growth", title: "Principles Over Moods", prompt: "Choose one principle to live by today — punctuality, kindness, honesty, follow-through — and hold to it regardless of your emotional state. The One integration teaches that integrity is not about feeling right; it is about doing right.", dayNumber: 16 },
  { id: 167, type: 4, category: "growth", title: "The Mundane as Sacred", prompt: "Fours seek the extraordinary and dismiss the mundane. Today, bring full attention to an ordinary task — washing dishes, making the bed, organizing a drawer. Let the One\'s appreciation for order and care transform the everyday into something meaningful.", dayNumber: 17 },
  { id: 168, type: 4, category: "growth", title: "Serving Something Larger", prompt: "Fours can become trapped in their inner world. Today, volunteer, help a neighbor, or contribute to a cause. The One\'s gift is the understanding that personal meaning often comes from serving something beyond the self.", dayNumber: 18 },
  { id: 169, type: 4, category: "growth", title: "Showing Up Consistently", prompt: "Fours are intense but inconsistent. Today, practice the One\'s consistency: show up on time, follow through on every commitment, respond to every message. Let reliability be a form of love — less romantic than grand gestures, but far more trustworthy.", dayNumber: 19 },
  { id: 170, type: 4, category: "growth", title: "The Action Antidote", prompt: "When melancholy descends today, do not sit with it indefinitely. After acknowledging the feeling, take one concrete action: clean a surface, write a paragraph, take a walk, make a call. The One integration teaches that action is the antidote to emotional paralysis — not its enemy.", dayNumber: 20 },
  { id: 171, type: 4, category: "mindfulness", title: "Emotional Weather Report", prompt: "As a heart-center type, your emotional life is rich but can become a storm that obscures clear seeing. Three times today, do an emotional weather report: \"Right now, the weather inside me is ___.\" Name it without judging it or becoming it. You are the sky, not the weather.", dayNumber: 21 },
  { id: 172, type: 4, category: "mindfulness", title: "The Heart-Space Meditation", prompt: "Place your hand on your heart. Breathe in, imagining your heart-space expanding. Breathe out, imagining it softening. For five minutes, simply feel the beating of your heart without interpreting it through the lens of longing, loss, or meaning.", dayNumber: 22 },
  { id: 173, type: 4, category: "mindfulness", title: "Grounding Out of the Story", prompt: "Fours can become lost in the narrative of their emotions. Today, when a feeling arises, feel it in your body first — before you attach a story. Where is the sadness? In your chest? Your throat? Stay with the sensation, not the interpretation.", dayNumber: 23 },
  { id: 174, type: 4, category: "mindfulness", title: "The Equanimity Breath", prompt: "Your virtue is equanimity — emotional balance. Practice this breath: inhale for four counts, hold for four, exhale for four, hold for four. Repeat for five minutes. Let the symmetry of the breath teach your emotional body that balance is not boredom — it is peace.", dayNumber: 24 },
  { id: 175, type: 4, category: "mindfulness", title: "Sensory Presence Practice", prompt: "Fours can be so deep in their inner world that they miss the outer one. Today, spend ten minutes in pure sensory awareness: five things you see, four you hear, three you touch, two you smell, one you taste. Let the physical world anchor you.", dayNumber: 25 },
  { id: 176, type: 4, category: "mindfulness", title: "Moving the Emotion", prompt: "When a heavy emotion settles in today, move it through your body rather than letting it stagnate. Dance to a song that matches your mood. Let your body express what words cannot. Movement transforms emotional energy from stasis to flow.", dayNumber: 26 },
  { id: 177, type: 4, category: "mindfulness", title: "The Self-Compassion Practice", prompt: "Fours are often compassionate toward others\' suffering but harsh about their own perceived deficiencies. Today, speak to yourself as you would to a beloved friend in pain: \"This is a difficult moment. Everyone struggles. May I be kind to myself.\"", dayNumber: 27 },
  { id: 178, type: 4, category: "mindfulness", title: "Breathing Into Envy", prompt: "When envy arises today, do not push it away or indulge it. Instead, breathe directly into the sensation of envy in your body. Where does it live — your stomach, your chest? Breathe into that space with compassion. Let the breath soften what wanting has hardened.", dayNumber: 28 },
  { id: 179, type: 4, category: "mindfulness", title: "The Gratitude Counter-Practice", prompt: "Fours naturally focus on what is missing. As a deliberate counter-practice, end today by writing ten things you are grateful for that are present in your life right now. Let gratitude coexist with longing without either one erasing the other.", dayNumber: 29 },
  { id: 180, type: 4, category: "mindfulness", title: "Body Appreciation", prompt: "Fours can have a fraught relationship with their body, wishing it were different, more beautiful, more expressive. Today, thank your body for one specific thing it does well — breathing, walking, hugging, tasting. Let appreciation replace aestheticization.", dayNumber: 30 },
  { id: 181, type: 4, category: "relationship", title: "Stable Presence", prompt: "Fours can be emotionally intense and unpredictable in relationships. Today, practice being a calm, steady presence for someone — not dramatic, not withdrawing, just reliably there. Let consistency be your offering rather than intensity.", dayNumber: 31 },
  { id: 182, type: 4, category: "relationship", title: "Seeing the Other Clearly", prompt: "Fours can idealize people when they are distant and devalue them when they are close. Today, look at someone important to you and see them as they actually are — neither perfect nor disappointing, but a real, complex human. Let that be enough.", dayNumber: 32 },
  { id: 183, type: 4, category: "relationship", title: "Expressing Without Overwhelming", prompt: "Today, share a feeling with someone using measured, clear language rather than the full intensity of your inner experience. \"I felt hurt when ___\" rather than a long, intense emotional monologue. Practice letting others receive your feelings in digestible doses.", dayNumber: 33 },
  { id: 184, type: 4, category: "relationship", title: "Appreciation Without Conditions", prompt: "Express genuine appreciation to someone today without qualifying it with what is still missing. Not \"I love you, but I wish...\" Just \"I love you.\" Let appreciation exist uncomplicated by longing for once.", dayNumber: 34 },
  { id: 185, type: 4, category: "relationship", title: "Resisting the Withdraw", prompt: "When you feel the urge to pull away from someone who cares about you today — because the closeness feels too ordinary or not intense enough — stay. Physically stay in the room, emotionally stay in the conversation. Let ordinariness be a form of love.", dayNumber: 35 },
  { id: 186, type: 4, category: "relationship", title: "Listening Without Comparing", prompt: "When someone shares their experience today, listen without internally comparing it to your own. Resist \"I understand because I...\" and instead say \"Tell me more about that.\" Let their experience exist on its own terms.", dayNumber: 36 },
  { id: 187, type: 4, category: "relationship", title: "The Repair After Drama", prompt: "If you created drama or emotional intensity in a relationship recently, today reach out with a simple, grounded repair. Not a dramatic apology, but a quiet one: \"I think I made things heavier than they needed to be. I am sorry.\"", dayNumber: 37 },
  { id: 188, type: 4, category: "relationship", title: "Asking About Others\' Inner Lives", prompt: "Fours are deeply attuned to their own inner world but can neglect others\'. Today, ask someone: \"What is going on inside you lately?\" and listen with genuine curiosity. You may discover that others are as deep and complex as you are.", dayNumber: 38 },
  { id: 189, type: 4, category: "relationship", title: "Celebrating Shared Humanity", prompt: "Instead of focusing on how you are different from others, today look for commonalities. What do you share with the people around you? What universal human experiences connect you? Let belonging coexist with individuality.", dayNumber: 39 },
  { id: 190, type: 4, category: "relationship", title: "The Non-Dramatic Love", prompt: "Practice expressing love in quiet, undramatic ways today: a brief text, a cup of tea made for someone, a steady gaze of appreciation. Let love be simple. The grand gesture is not always the deepest one.", dayNumber: 40 },
  { id: 191, type: 4, category: "affirmation", title: "\"What I am seeking is already here.\"", prompt: "Repeat this when longing arises. The Four\'s endless search for what is missing often blinds you to what is present. Place your hands on the surface in front of you and feel its solidity. Reality is here. You are in it.", dayNumber: 41 },
  { id: 192, type: 4, category: "affirmation", title: "\"I am not my emotions — I am the awareness that holds them.\"", prompt: "Use this when emotions threaten to consume you. You are vast enough to contain sadness, joy, envy, and peace all at once. No single feeling defines you.", dayNumber: 42 },
  { id: 193, type: 4, category: "affirmation", title: "\"My life does not need to be extraordinary to be meaningful.\"", prompt: "This is the Four\'s most healing mantra. Say it when you feel the gap between your life and your ideal. Meaning does not require drama. A quiet life, fully felt, is as significant as an epic one.", dayNumber: 43 },
  { id: 194, type: 4, category: "affirmation", title: "\"Envy is a signpost, not a sentence.\"", prompt: "When envy arises, use this mantra to transform it from suffering into information. What you envy shows you what you desire. Once you see the desire clearly, you can pursue it — or choose to release it.", dayNumber: 44 },
  { id: 195, type: 4, category: "affirmation", title: "\"I belong here, just as I am.\"", prompt: "Fours often feel like outsiders. Say this when you feel excluded, alien, or misunderstood. You do not need to be different to belong. You do not need to be understood to be worthy of belonging.", dayNumber: 45 },
  { id: 196, type: 4, category: "affirmation", title: "\"I can feel deeply and still act.\"", prompt: "Use this when emotions paralyze you. Depth of feeling is your gift, but it does not have to be your cage. You can feel the full weight of an emotion and still take the next step.", dayNumber: 46 },
  { id: 197, type: 4, category: "affirmation", title: "\"Ordinary moments contain the sacred.\"", prompt: "Say this during the mundane parts of your day. The extraordinary you seek is woven into the fabric of the ordinary. The light through the window, the warmth of a mug, the steadiness of your breath — all of it is luminous if you let it be.", dayNumber: 47 },
  { id: 198, type: 4, category: "affirmation", title: "\"I release the story that something is wrong with me.\"", prompt: "This addresses the Four\'s core wound: the belief in a fundamental flaw. Today, each time this belief surfaces, say this mantra and feel the relief of putting down a burden you were never meant to carry.", dayNumber: 48 },
  { id: 199, type: 4, category: "affirmation", title: "\"Equanimity is not emptiness — it is spacious peace.\"", prompt: "Fours fear that balance means losing emotional depth. This mantra reminds you that equanimity is not flatness — it is the vast, peaceful space in which all emotions can arise without overwhelming you.", dayNumber: 49 },
  { id: 200, type: 4, category: "affirmation", title: "\"I am already whole. The search can end.\"", prompt: "Use this as a closing meditation. The Four\'s lifelong search for the missing piece — the ideal partner, the perfect career, the lost homeland of the soul — can soften. You are not broken. You are not incomplete. You are here, and you are whole.", dayNumber: 50 },
  { id: 201, type: 5, category: "shadow", title: "The Withdrawal Audit", prompt: "Track today how often you withdraw — from conversations, from invitations, from emotional moments. For each withdrawal, ask: \"What am I protecting?\" Fives retreat to conserve energy, but sometimes what feels like conservation is actually deprivation.", dayNumber: 1 },
  { id: 202, type: 5, category: "shadow", title: "The Hoarding Inventory", prompt: "Avarice in Fives is not about money — it is about hoarding time, energy, knowledge, and privacy. Journal about what you are hoarding right now. What would it cost you to share more freely? What abundance might flow in if you loosened your grip?", dayNumber: 2 },
  { id: 203, type: 5, category: "shadow", title: "The Body You Have Abandoned", prompt: "Fives often live from the neck up, treating the body as a vehicle for the mind. Right now, close your eyes and feel your body. When was the last time you attended to a physical sensation — hunger, fatigue, tension, pleasure — before it became urgent? Your body has been speaking. Have you been listening?", dayNumber: 3 },
  { id: 204, type: 5, category: "shadow", title: "Emotional Minimalism as Defense", prompt: "Fives pride themselves on not being \"emotional,\" but this often masks a fear of being overwhelmed by feelings. Today, allow one emotion to be larger than usual. If sadness comes, let it be a wave rather than a trickle. Your emotional capacity is greater than you believe.", dayNumber: 4 },
  { id: 205, type: 5, category: "shadow", title: "The Observer Trap", prompt: "Notice today when you are observing life rather than participating in it. Watching a gathering rather than joining. Analyzing a conversation rather than being in it. Ask: \"Am I studying life as a substitute for living it?\"", dayNumber: 5 },
  { id: 206, type: 5, category: "shadow", title: "The Competence Shield", prompt: "Fives use knowledge as armor. Today, journal about what you believe would happen if people saw you as incompetent. What catastrophe do you imagine? Underneath the need to know is often a terrified child who believes that understanding is the only thing keeping them safe.", dayNumber: 6 },
  { id: 207, type: 5, category: "shadow", title: "Scarcity Thinking", prompt: "Fives operate from a deep sense of scarcity: not enough time, not enough energy, not enough inner resources to meet the world\'s demands. Today, challenge this assumption. What if you have more than enough? What if engaging with life replenishes rather than depletes you?", dayNumber: 7 },
  { id: 208, type: 5, category: "shadow", title: "The Ivory Tower", prompt: "Fives can build elaborate inner worlds that become more real than the outer one. Today, notice when you retreat into your mind to avoid discomfort. What would happen if you stayed present in the messy, demanding, uncontrollable outer world instead?", dayNumber: 8 },
  { id: 209, type: 5, category: "shadow", title: "Detachment vs. Non-Attachment", prompt: "Your virtue is non-attachment, but your shadow is detachment. Non-attachment means engaging fully while holding outcomes loosely. Detachment means not engaging at all. Journal about where in your life you have confused the two.", dayNumber: 9 },
  { id: 210, type: 5, category: "shadow", title: "The Need Beneath the Independence", prompt: "Fives cultivate radical independence to avoid needing anyone. But need is not weakness — it is human. Today, privately journal about what you genuinely need from others: companionship, touch, reassurance, help. Let yourself feel the vulnerability of these needs.", dayNumber: 10 },
  { id: 211, type: 5, category: "growth", title: "Take Up Space", prompt: "At your integration point, you access the Eight\'s gift of assertive presence. Today, practice taking up more space: speak louder, sit wider, make a bold request, state your opinion without hedging. Let yourself be physically and socially larger than your instinct allows.", dayNumber: 11 },
  { id: 212, type: 5, category: "growth", title: "The Body Engagement Practice", prompt: "Eights are viscerally embodied. Today, do something intensely physical: lift weights, chop wood, run until you are breathless, dance vigorously. Let your body remind your mind that you are a physical creature with power and vitality.", dayNumber: 12 },
  { id: 213, type: 5, category: "growth", title: "Decisive Action", prompt: "Fives can over-research and under-act. Today, make one decision you have been delaying — not after more analysis, but right now with the information you have. The Eight integration teaches that imperfect action beats perfect paralysis.", dayNumber: 13 },
  { id: 214, type: 5, category: "growth", title: "Confrontation Practice", prompt: "Fives avoid confrontation by withdrawing. Today, address one thing that is bothering you directly with the person involved. Not aggressively, but firmly: \"I need to tell you something.\" The Eight\'s gift is the courage to be direct.", dayNumber: 14 },
  { id: 215, type: 5, category: "growth", title: "Protecting Someone", prompt: "Eights are natural protectors. Today, use your knowledge and perception to advocate for someone who cannot advocate for themselves. Write a letter, make a call, speak up in a meeting. Let your intellect serve the Eight\'s instinct for justice.", dayNumber: 15 },
  { id: 216, type: 5, category: "growth", title: "Generous Sharing of Knowledge", prompt: "Instead of hoarding your expertise, today teach someone something you know. Share freely and abundantly. The Eight\'s energy is expansive and generous. Let your knowledge flow outward rather than accumulating inward.", dayNumber: 16 },
  { id: 217, type: 5, category: "growth", title: "The Gut Decision", prompt: "Fives rely on analysis; Eights trust their gut. Today, make one choice based purely on instinct — what your body says, what your gut tells you — without consulting research, data, or deliberation. Trust the animal intelligence that lives below thought.", dayNumber: 17 },
  { id: 218, type: 5, category: "growth", title: "Claiming Your Anger", prompt: "Fives suppress anger because it feels messy and irrational. But anger is also power, boundary, and life force. Today, let yourself feel angry about something that matters. Do not intellectualize it. Let it burn. The Eight integration restores your relationship with anger as fuel.", dayNumber: 18 },
  { id: 219, type: 5, category: "growth", title: "Leading Rather Than Advising", prompt: "Fives prefer to advise from the sidelines rather than lead from the front. Today, step into a leadership role — organize something, delegate tasks, make the plan. The Eight teaches that leading is not about knowing everything; it is about moving forward with conviction.", dayNumber: 19 },
  { id: 220, type: 5, category: "growth", title: "Engaging With Intensity", prompt: "The Eight lives at full volume. Today, bring intensity to one experience: eat a meal slowly and savor every flavor, listen to music at full volume, have a conversation where you are fully emotionally present. Replace detached observation with immersed participation.", dayNumber: 20 },
  { id: 221, type: 5, category: "mindfulness", title: "The Embodiment Alarm", prompt: "As a head-center type, you live primarily in your mind. Set five alarms today. At each alarm, leave your thoughts and enter your body for sixty seconds. Feel your feet, your hands, your breathing, the temperature of the air. Train your attention to inhabit your physical form.", dayNumber: 21 },
  { id: 222, type: 5, category: "mindfulness", title: "Warm Hands Practice", prompt: "Fives often have cold hands and feet — a sign of the body pulling energy inward. Today, rub your hands together until they are warm, then place them on your belly. Feel the warmth spread. This simple practice reverses the body\'s withdrawal and signals safety.", dayNumber: 22 },
  { id: 223, type: 5, category: "mindfulness", title: "The Two-Minute Engagement", prompt: "When you feel the urge to retreat — from a conversation, a social event, a moment of closeness — commit to staying for just two more minutes. Often, the discomfort that triggers withdrawal passes quickly, and what remains is connection.", dayNumber: 23 },
  { id: 224, type: 5, category: "mindfulness", title: "Breathing Into the Belly", prompt: "Fives breathe shallowly, keeping energy in the head. Today, practice belly breathing for five minutes: deep inhale expanding the belly, long exhale letting it fall. With each breath, imagine moving your center of gravity from your head to your gut.", dayNumber: 24 },
  { id: 225, type: 5, category: "mindfulness", title: "Sensory Immersion", prompt: "Choose one sensory experience today and immerse in it completely: the taste of coffee, the texture of fabric, the sound of rain. Let the experience be purely physical, resisting the urge to analyze or categorize it. Be in the sensation, not above it.", dayNumber: 25 },
  { id: 226, type: 5, category: "mindfulness", title: "The Energy Inventory", prompt: "Fives closely monitor their energy levels. Today, notice when your energy actually increases — after a good conversation, a physical activity, a moment of connection. You may discover that engagement is not always draining. Sometimes it is the source of energy.", dayNumber: 26 },
  { id: 227, type: 5, category: "mindfulness", title: "Progressive Muscle Relaxation", prompt: "Lie down and systematically tense and release every muscle group from feet to face. Fives carry tension they do not notice because they are disconnected from their bodies. This practice reintroduces you to the body you have been neglecting.", dayNumber: 27 },
  { id: 228, type: 5, category: "mindfulness", title: "The Anxiety Breath", prompt: "When mental spiraling begins — the infinite loop of analysis — use this pattern: breathe in for four counts, hold for seven, exhale for eight. This activates the vagus nerve and physiologically interrupts the head center\'s overthinking.", dayNumber: 28 },
  { id: 229, type: 5, category: "mindfulness", title: "Cold Water Awakening", prompt: "Splash cold water on your face or end your shower with thirty seconds of cold water. The shock of cold reconnects Fives to their physical body immediately. It is difficult to be trapped in your head when cold water is demanding your body\'s full attention.", dayNumber: 29 },
  { id: 230, type: 5, category: "mindfulness", title: "The Meal as Meditation", prompt: "Eat one meal today in complete silence, with no reading, no screen, no mental problem-solving. Taste each bite. Feel the texture. Notice when you are full. For Fives, eating mindfully is a radical act of embodiment — treating the body as worthy of attention.", dayNumber: 30 },
  { id: 231, type: 5, category: "relationship", title: "Initiating Contact", prompt: "Fives wait to be invited rather than initiating. Today, reach out to someone first — send a message, make a call, suggest a plan. Do not wait until you feel ready. The act of reaching out is the practice.", dayNumber: 31 },
  { id: 232, type: 5, category: "relationship", title: "Staying in the Room", prompt: "When a conversation becomes emotionally intense, Fives disappear — mentally if not physically. Today, when you feel the pull to retreat during an emotional moment, stay present. Say: \"I am here. This is hard for me, but I am here.\"", dayNumber: 32 },
  { id: 233, type: 5, category: "relationship", title: "Sharing Before You Are Ready", prompt: "Fives wait until they have fully formulated their thoughts before sharing. Today, practice thinking out loud with someone. Share an idea that is still half-formed. Let them see your process, not just your polished conclusions.", dayNumber: 33 },
  { id: 234, type: 5, category: "relationship", title: "Physical Affection Stretch", prompt: "If you are comfortable with the person, today initiate physical contact: a hug, a hand on someone\'s shoulder, sitting close. Fives often maintain physical distance as a form of boundary. Let your body communicate warmth that your words may struggle to express.", dayNumber: 34 },
  { id: 235, type: 5, category: "relationship", title: "The Vulnerability Experiment", prompt: "Tell someone you trust about a fear, an insecurity, or a struggle — not as an intellectual observation, but as a felt experience. \"I am afraid of ___\" or \"I struggle with ___.\" Let yourself be seen without the armor of analysis.", dayNumber: 35 },
  { id: 236, type: 5, category: "relationship", title: "Active Listening Without Solving", prompt: "When someone shares a problem today, resist the urge to immediately analyze or solve it. Instead, reflect back what they said: \"It sounds like you are feeling ___.\" Let emotional resonance replace intellectual problem-solving.", dayNumber: 36 },
  { id: 237, type: 5, category: "relationship", title: "Giving Your Time", prompt: "Time is what Fives guard most fiercely. Today, give someone more time than feels comfortable. Stay in a conversation longer than planned. Accept an invitation you would normally decline. Let generosity with time be your practice.", dayNumber: 37 },
  { id: 238, type: 5, category: "relationship", title: "The \"I Need You\" Practice", prompt: "Say to someone today, in whatever words feel authentic: \"I need you in my life\" or \"I value your presence\" or \"I would be diminished without you.\" Let someone know they matter to you. Fives often feel this deeply but rarely express it.", dayNumber: 38 },
  { id: 239, type: 5, category: "relationship", title: "Showing Up Physically", prompt: "Attend something in person that you could do remotely. Go to the meeting, the gathering, the dinner. Your physical presence communicates investment and care in a way that a message or email cannot.", dayNumber: 39 },
  { id: 240, type: 5, category: "relationship", title: "Responding in Real Time", prompt: "Fives delay responding to messages and emails while they formulate the perfect reply. Today, respond to three messages immediately and imperfectly. Let \"good enough\" communication strengthen your relationships more than delayed perfection.", dayNumber: 40 },
  { id: 241, type: 5, category: "affirmation", title: "\"I have enough energy to meet this moment.\"", prompt: "Repeat this when you feel the urge to withdraw and conserve. You are not as depleted as your mind tells you. This moment — just this one — is manageable. Trust your capacity.", dayNumber: 41 },
  { id: 242, type: 5, category: "affirmation", title: "\"Connection nourishes me — it does not deplete me.\"", prompt: "Use this before social interactions. The Five\'s assumption is that people drain energy. But real connection can be a source of vitality. Let this mantra open the door to the possibility of being replenished by others.", dayNumber: 42 },
  { id: 243, type: 5, category: "affirmation", title: "\"I am safe in my body.\"", prompt: "Fives retreat to the mind because the body and emotions feel unsafe. Say this while placing your hands on your torso. The body is not a threat. It is your home. You can live in it without being overwhelmed.", dayNumber: 43 },
  { id: 244, type: 5, category: "affirmation", title: "\"My knowledge does not need to be complete before I act.\"", prompt: "Use this when analysis paralysis strikes. You will never know enough to guarantee a perfect outcome. But you know enough right now to take the next step. Let this mantra release you from the prison of preparation.", dayNumber: 44 },
  { id: 245, type: 5, category: "affirmation", title: "\"I can be generous with my presence.\"", prompt: "Fives ration their presence as though it were a finite resource. Today, let this mantra remind you that showing up for others does not diminish you. Your presence is renewable, and sharing it creates more of it.", dayNumber: 45 },
  { id: 246, type: 5, category: "affirmation", title: "\"Emotions are information, not threats.\"", prompt: "When feelings arise and your instinct is to detach, say this. Emotions are not invaders — they are messengers. You can receive the message without being consumed. Your analytical mind and your emotional heart can work together.", dayNumber: 46 },
  { id: 247, type: 5, category: "affirmation", title: "\"The world needs my participation, not just my observations.\"", prompt: "Use this when you find yourself on the sidelines. You have insights, ideas, and gifts that only become real when shared. Observation is preparation; participation is contribution.", dayNumber: 47 },
  { id: 248, type: 5, category: "affirmation", title: "\"I do not need to understand everything to trust this moment.\"", prompt: "This is the Five\'s surrender: letting go of the need for comprehensive understanding. Some things are experienced, not understood. Let this mantra invite you into the mystery of being alive.", dayNumber: 48 },
  { id: 249, type: 5, category: "affirmation", title: "\"Vulnerability is the beginning of real strength.\"", prompt: "Fives equate vulnerability with weakness, but the Eight integration reveals the opposite. The courage to be vulnerable — to need, to feel, to risk — is the deepest form of strength.", dayNumber: 49 },
  { id: 250, type: 5, category: "affirmation", title: "\"I am more than my mind — I am a whole, embodied being.\"", prompt: "Use this as a closing practice. Stand up, feel your body, move your arms. You are not a brain in a jar. You are a living, breathing, feeling creature with a body that deserves to be inhabited. Welcome yourself home.", dayNumber: 50 },
  { id: 251, type: 6, category: "shadow", title: "The Anxiety Autopsy", prompt: "Write down your three biggest current worries. For each one, ask: \"What is the worst-case scenario?\" Then: \"How likely is this, really? And if it happened, what resources would I have to handle it?\" Notice the gap between the intensity of the fear and the actual probability.", dayNumber: 1 },
  { id: 252, type: 6, category: "shadow", title: "Projection Awareness", prompt: "Sixes project their own fears and motives onto others. Today, when you suspect someone\'s intentions, pause and ask: \"Is this what they are actually doing, or is this what I fear they might be doing?\" Journal about one situation where your projection may not match reality.", dayNumber: 2 },
  { id: 253, type: 6, category: "shadow", title: "The Authority Dance", prompt: "Sixes have a complex relationship with authority — they either seek it for reassurance or rebel against it for autonomy. Today, notice how you relate to authority figures. Do you defer? Resist? Test? What would it look like to relate to authority from a place of inner security rather than anxiety?", dayNumber: 3 },
  { id: 254, type: 6, category: "shadow", title: "Worst-Case Addiction", prompt: "Sixes mentally rehearse catastrophes as a way to feel prepared. But this preparation is often just anxiety wearing a productive mask. Today, when you catch yourself spinning worst-case scenarios, ask: \"Is this planning, or is this worry disguised as planning?\"", dayNumber: 4 },
  { id: 255, type: 6, category: "shadow", title: "The Doubt Loop", prompt: "Notice today when doubt spirals: questioning a decision you have made, second-guessing your instincts, seeking one more opinion. When you catch the loop, write down: \"I have enough information. I can trust myself.\" Doubt is not wisdom — it is your fixation.", dayNumber: 5 },
  { id: 256, type: 6, category: "shadow", title: "Testing Others\' Loyalty", prompt: "Sixes sometimes test people to see if they will stay — picking fights, withdrawing, creating scenarios that force others to prove their commitment. Journal honestly: have you done this recently? What were you really looking for? What would it mean to trust without testing?", dayNumber: 6 },
  { id: 257, type: 6, category: "shadow", title: "The Safety Addiction", prompt: "What are you organizing your entire life around avoiding? Journal about the threats — real or imagined — that drive your daily decisions. Then ask: \"If I were not afraid of this, how would I live differently?\" The distance between those two lives is the cost of anxiety.", dayNumber: 7 },
  { id: 258, type: 6, category: "shadow", title: "Phobic vs. Counterphobic", prompt: "Sixes respond to fear in two ways: avoiding what scares them (phobic) or charging toward it aggressively (counterphobic). Which pattern is yours? Today, notice when fear arises and how you respond. Neither pattern addresses the fear itself — both are reactions to it.", dayNumber: 8 },
  { id: 259, type: 6, category: "shadow", title: "The Reassurance Habit", prompt: "How many times today did you seek reassurance — asking if something is okay, checking if someone is upset, confirming a plan, Googling a symptom? Count them. Each instance of reassurance-seeking temporarily soothes anxiety but reinforces the belief that you cannot trust yourself.", dayNumber: 9 },
  { id: 260, type: 6, category: "shadow", title: "The Courage Beneath the Fear", prompt: "Your virtue is courage — not the absence of fear, but action in spite of it. Journal about a time you were afraid and acted anyway. What happened? What did you learn about yourself? You have been brave before. You can be brave again.", dayNumber: 10 },
  { id: 261, type: 6, category: "growth", title: "The Trust Fall Into the Present", prompt: "At your integration point, you access the Nine\'s gift of inner peace and trust in the unfolding of life. Today, when anxiety arises about the future, practice returning to this exact moment. Right now, in this breath, you are okay. Let the present moment be enough.", dayNumber: 11 },
  { id: 262, type: 6, category: "growth", title: "The Relaxation Challenge", prompt: "Sixes carry tension as a baseline state. Today, deliberately relax for 20 minutes: a bath, gentle stretching, lying in grass, sitting in sunlight. Do not relax \"in order to\" be more productive later. Relax as an end in itself. The Nine knows that rest is not a strategy — it is a birthright.", dayNumber: 12 },
  { id: 263, type: 6, category: "growth", title: "Letting Go of Vigilance", prompt: "For one hour today, consciously let go of scanning for threats. Do not check your email, the news, or your messages. Trust that the world will hold together without your watchfulness. The Nine integration teaches that constant vigilance is not keeping you safe — it is keeping you anxious.", dayNumber: 13 },
  { id: 264, type: 6, category: "growth", title: "The \"It Will Work Out\" Practice", prompt: "When worry arises about a situation today, say to yourself: \"It will work out. Maybe not how I expect, but it will work out.\" This is not naive optimism — it is the Nine\'s deep trust in the resilience of life. You have survived every difficult day so far.", dayNumber: 14 },
  { id: 265, type: 6, category: "growth", title: "Merging With Nature", prompt: "Nines have a natural affinity for the rhythms of nature. Today, spend time outdoors without an agenda. Sit under a tree, watch clouds, listen to birds. Let the natural world remind you that existence itself is trustworthy, even when your mind insists otherwise.", dayNumber: 15 },
  { id: 266, type: 6, category: "growth", title: "Accepting Ambiguity", prompt: "Sixes want certainty. The Nine integration invites you to make peace with not knowing. Today, choose one uncertain situation and practice holding it without resolving it. Say: \"I do not know how this will turn out, and I can be at peace with that.\"", dayNumber: 16 },
  { id: 267, type: 6, category: "growth", title: "The Inner Calm Visualization", prompt: "Close your eyes and imagine a place of absolute safety — a mountain lake, a sunlit room, an ancient forest. Spend five minutes there in your mind. This is not escapism; it is accessing the Nine\'s inner landscape of peace. You can return here whenever anxiety surges.", dayNumber: 17 },
  { id: 268, type: 6, category: "growth", title: "Seeing Multiple Perspectives", prompt: "Nines see all sides of a situation. Today, take one person you distrust or are anxious about and genuinely try to see the situation from their perspective. Not to be naive, but to soften the rigid either/or thinking that anxiety produces.", dayNumber: 18 },
  { id: 269, type: 6, category: "growth", title: "The Non-Urgency Practice", prompt: "Sixes treat everything as urgent. Today, deliberately de-escalate one situation you have been treating as an emergency. Ask: \"Does this truly need to be resolved today?\" Give yourself permission to let it wait. The Nine integration teaches that most things are less urgent than anxiety claims.", dayNumber: 19 },
  { id: 270, type: 6, category: "growth", title: "Trusting Your Own Ground", prompt: "The Nine is grounded and self-possessed. Today, when you feel the urge to seek external validation or reassurance, turn inward instead. Place your hand on your belly. Breathe. Ask: \"What do I already know to be true?\" Trust the answer that arises from your own center.", dayNumber: 20 },
  { id: 271, type: 6, category: "mindfulness", title: "The Anxiety Location Practice", prompt: "When anxiety arises, locate it in your body. Is it in your chest? Your stomach? Your throat? Instead of following the mental story, stay with the physical sensation. Breathe into it. Anxiety lives in the body; working with it somatically is often more effective than analyzing it.", dayNumber: 21 },
  { id: 272, type: 6, category: "mindfulness", title: "The 5-4-3-2-1 Grounding", prompt: "When spiraling begins, anchor yourself in the senses: name five things you see, four you hear, three you can touch, two you smell, one you taste. This technique pulls you out of the head center\'s catastrophizing and into the present moment.", dayNumber: 22 },
  { id: 273, type: 6, category: "mindfulness", title: "Shaking Off the Worry", prompt: "Animals shake off stress after a threat passes. Stand up and literally shake your whole body for two minutes — hands, arms, legs, shoulders. Let the accumulated tension of hyper-vigilance discharge through movement. This is your nervous system\'s natural reset.", dayNumber: 23 },
  { id: 274, type: 6, category: "mindfulness", title: "The Long Exhale", prompt: "Anxiety activates the sympathetic nervous system; long exhales activate the parasympathetic. Today, practice exhaling for twice as long as you inhale (in for 4, out for 8). Do this for three minutes whenever anxiety spikes. You are manually switching your nervous system from alarm to calm.", dayNumber: 24 },
  { id: 275, type: 6, category: "mindfulness", title: "Grounding Through Your Feet", prompt: "When fear escalates, press your feet firmly into the ground. Feel the solid surface beneath you. Wiggle your toes. The head center\'s fears live in the future; your feet exist only in the present. Let your feet teach your mind where you actually are.", dayNumber: 25 },
  { id: 276, type: 6, category: "mindfulness", title: "The Body Scan for Safety", prompt: "Lie down and slowly scan your body, asking at each area: \"Are you safe right now?\" Feet — safe. Legs — safe. Belly — safe. Proceed upward. You may find that your body is safe in this moment, even if your mind is rehearsing danger. Let the body\'s evidence overrule the mind\'s speculation.", dayNumber: 26 },
  { id: 277, type: 6, category: "mindfulness", title: "Jaw Release Practice", prompt: "Sixes clench their jaw — it is the body bracing for impact. Throughout today, consciously unclench your jaw. Let your mouth fall slightly open. Relax your tongue from the roof of your mouth. Each release is a signal to your nervous system that no impact is coming.", dayNumber: 27 },
  { id: 278, type: 6, category: "mindfulness", title: "Walking Meditation for the Anxious Mind", prompt: "Walk slowly for ten minutes, feeling each step: heel, arch, toes. Coordinate your breathing with your steps. When your mind races ahead to worries, bring it back to the foot meeting the ground. You are practicing the skill of being where you are.", dayNumber: 28 },
  { id: 279, type: 6, category: "mindfulness", title: "The Courage Breath", prompt: "Before any situation that triggers anxiety — a meeting, a confrontation, an uncertain moment — take three deep breaths and say internally with each exhale: \"Courage.\" You are not eliminating fear. You are breathing alongside it and choosing to act anyway.", dayNumber: 29 },
  { id: 280, type: 6, category: "mindfulness", title: "Evening Discharge Ritual", prompt: "Before bed, sit quietly and mentally review the day\'s anxieties. For each one, imagine placing it in a box and setting the box outside your door. You can pick it up tomorrow if you still need it. Tonight, your nervous system gets to rest. The world will not fall apart while you sleep.", dayNumber: 30 },
  { id: 281, type: 6, category: "relationship", title: "Trusting Without Testing", prompt: "Today, practice trusting someone without testing them first. Take their words at face value. If they say they are fine, believe them. If they make a promise, assume they will keep it. Let trust be a practice rather than a conclusion.", dayNumber: 31 },
  { id: 282, type: 6, category: "relationship", title: "Expressing Fear Without Spiraling", prompt: "When you feel anxious about a relationship today, express it directly: \"I am feeling insecure about us right now.\" Not as an accusation, not as a test, but as honest vulnerability. Let your partner or friend help you hold the fear rather than managing it alone.", dayNumber: 32 },
  { id: 283, type: 6, category: "relationship", title: "Releasing Suspicion", prompt: "Identify one person you have been suspicious of — their motives, their loyalty, their honesty. Today, consciously choose to extend the benefit of the doubt. Write down three generous interpretations of their behavior. You may be right to be cautious — but you may also be projecting.", dayNumber: 33 },
  { id: 284, type: 6, category: "relationship", title: "Asking for Reassurance Openly", prompt: "Instead of testing people indirectly, today practice asking directly for what you need: \"I need to hear that we are okay.\" \"Can you tell me you are not upset with me?\" Direct requests are vulnerable, but they are more honest than the testing games anxiety designs.", dayNumber: 34 },
  { id: 285, type: 6, category: "relationship", title: "The Loyalty Overflow", prompt: "Sixes are fiercely loyal, but this loyalty can become possessive or anxious. Today, practice generous loyalty: support someone\'s independence, celebrate their other friendships, encourage them to take a risk. Love them by letting them be free.", dayNumber: 35 },
  { id: 286, type: 6, category: "relationship", title: "Handling Disagreement Without Catastrophizing", prompt: "The next time someone disagrees with you, practice staying in the conversation without assuming it threatens the relationship. A disagreement is not an abandonment. Say to yourself: \"We can disagree and still be connected.\"", dayNumber: 36 },
  { id: 287, type: 6, category: "relationship", title: "Being a Calm Presence", prompt: "Sixes can inadvertently spread their anxiety to others. Today, practice being a calm presence: speak slowly, listen fully, do not voice every worry. You do not need to process every fear aloud. Sometimes the greatest gift to others is your composure.", dayNumber: 37 },
  { id: 288, type: 6, category: "relationship", title: "Commitment Without Exit Strategies", prompt: "Sixes secretly maintain exit strategies in relationships. Today, notice if you are mentally rehearsing how you would handle a breakup, a firing, or a betrayal. Then consciously choose to invest in the relationship as though it will last. Be fully in it.", dayNumber: 38 },
  { id: 289, type: 6, category: "relationship", title: "The Authority Conversation", prompt: "Have an honest conversation with someone you view as an authority figure — a boss, a parent, a mentor — where you express a genuine opinion that might conflict with theirs. Practice standing in your own authority rather than seeking theirs.", dayNumber: 39 },
  { id: 290, type: 6, category: "relationship", title: "Sharing Your Strength", prompt: "Sixes often focus on their vulnerabilities and underestimate their strengths. Today, tell someone about something you are genuinely good at or proud of. Let yourself be seen as capable, not just cautious. Your strength is as real as your fear.", dayNumber: 40 },
  { id: 291, type: 6, category: "affirmation", title: "\"I am safe in this moment.\"", prompt: "Repeat this whenever anxiety spikes. Not \"I will always be safe\" — that is a promise no one can keep. But right now, in this breath, in this moment, you are safe. Let this truth anchor you to the present.", dayNumber: 41 },
  { id: 292, type: 6, category: "affirmation", title: "\"I can handle whatever comes.\"", prompt: "This is not denial — it is an acknowledgment of your resilience. You have handled every challenge life has delivered so far. You are more resourceful than your anxiety gives you credit for.", dayNumber: 42 },
  { id: 293, type: 6, category: "affirmation", title: "\"Courage is not the absence of fear — it is moving forward with fear.\"", prompt: "Your virtue is courage. Say this when fear tells you to retreat. You do not need to wait until you are not afraid. You can be afraid and brave at the same time.", dayNumber: 43 },
  { id: 294, type: 6, category: "affirmation", title: "\"I trust myself.\"", prompt: "Three simple words that address the Six\'s core wound. The endless seeking of guidance, reassurance, and authority is rooted in a distrust of your own inner knowing. Today, each time you seek external validation, say this first and see if the answer is already within you.", dayNumber: 44 },
  { id: 295, type: 6, category: "affirmation", title: "\"Not every thought is true.\"", prompt: "When your mind generates a frightening scenario, say this. Thoughts are not reality. Especially anxious thoughts, which are your mind\'s attempt to prepare for danger — not evidence that danger is imminent.", dayNumber: 45 },
  { id: 296, type: 6, category: "affirmation", title: "\"I release the need to know what happens next.\"", prompt: "Use this when the compulsion to plan, prepare, and control the future becomes overwhelming. The future is unknowable. Releasing the need to know is not reckless — it is the beginning of peace.", dayNumber: 46 },
  { id: 297, type: 6, category: "affirmation", title: "\"My anxiety does not protect me — my courage does.\"", prompt: "Sixes often believe that worrying keeps them safe. This mantra gently corrects that belief. Anxiety is not a security system. It is a false alarm that fires continuously. Courage is the true protector.", dayNumber: 47 },
  { id: 298, type: 6, category: "affirmation", title: "\"I am supported by life itself.\"", prompt: "When you feel alone and without guidance, say this. The support you seek is not only in institutions or authority figures — it is in the ground beneath your feet, the air in your lungs, and the deep intelligence of life unfolding.", dayNumber: 48 },
  { id: 299, type: 6, category: "affirmation", title: "\"Doubt is a visitor, not a resident.\"", prompt: "When doubt arrives — about your decisions, your relationships, your worthiness — greet it as a passing visitor. \"Hello, doubt. I see you. You can visit, but you do not live here.\" Let it pass through without setting up camp.", dayNumber: 49 },
  { id: 300, type: 6, category: "affirmation", title: "\"I choose trust over fear today.\"", prompt: "Use this as a morning intention. Not blind trust, but a deliberate choice to lean toward faith rather than suspicion. Today, when you stand at the fork between trust and fear, take the path of trust and see where it leads.", dayNumber: 50 },
  { id: 301, type: 7, category: "shadow", title: "The Pain You Are Running From", prompt: "Sevens stay in motion to outrun pain. Right now, sit still and ask: \"What am I avoiding feeling?\" There is something underneath the busyness, the plans, the excitement. It might be grief, loneliness, fear, or a deep sadness you have never fully faced. Let it surface, even briefly.", dayNumber: 1 },
  { id: 302, type: 7, category: "shadow", title: "The FOMO Excavation", prompt: "Notice today when the fear of missing out drives a decision — checking another option, saying yes to too many things, scrolling for something better. For each instance, ask: \"What am I afraid I will miss? And what am I actually missing by not being fully here?\"", dayNumber: 2 },
  { id: 303, type: 7, category: "shadow", title: "The Commitment Autopsy", prompt: "List three commitments you have abandoned — a project, a relationship, a practice. For each one, journal about the moment you lost interest. Was it genuinely not right for you, or did you leave when it stopped being novel and started requiring depth?", dayNumber: 3 },
  { id: 304, type: 7, category: "shadow", title: "Superficiality as Shield", prompt: "Sevens can be the life of the party while remaining emotionally unavailable. Today, notice when you use humor, enthusiasm, or storytelling to keep things light and avoid going deep. What would the conversation look like if you dropped the performance?", dayNumber: 4 },
  { id: 305, type: 7, category: "shadow", title: "The Gluttony Audit", prompt: "Your passion is gluttony — not for food, but for experience, stimulation, and options. Today, notice your consumption patterns: how many tabs are open, how many plans are in motion, how many options you keep alive. What would it feel like to have less?", dayNumber: 5 },
  { id: 306, type: 7, category: "shadow", title: "Reframing as Avoidance", prompt: "Sevens are masters of positive reframing, but this gift becomes a shadow when it prevents you from fully feeling difficult experiences. Today, when something painful happens, resist the urge to immediately find the silver lining. Let the pain be painful first. The meaning will come later.", dayNumber: 6 },
  { id: 307, type: 7, category: "shadow", title: "The Boredom Terror", prompt: "For Sevens, boredom is not mild discomfort — it is existential threat. Sit in an empty room for fifteen minutes with no phone, no book, no stimulus. When boredom arises, do not flee. Investigate it. What does boredom feel like in your body? What is underneath it?", dayNumber: 7 },
  { id: 308, type: 7, category: "shadow", title: "The Scattered Mind", prompt: "Sevens spread their attention across many things to avoid depth in any one. Today, notice how many times your mind jumps between topics, plans, and ideas within a single hour. Count the jumps. This scatteredness is not creativity — it is anxiety wearing a party hat.", dayNumber: 8 },
  { id: 309, type: 7, category: "shadow", title: "The Escape Hatch Inventory", prompt: "How many escape hatches do you maintain? A backup plan for your relationship, a fantasy career, a \"someday\" trip that keeps you from fully investing in the life you have. Journal about what you are keeping one foot outside of — and why.", dayNumber: 9 },
  { id: 310, type: 7, category: "shadow", title: "Sitting With Grief", prompt: "Sevens avoid grief more than any other type. Today, let yourself grieve something — a loss, a missed opportunity, the passage of time, the life you imagined versus the one you have. Give grief fifteen minutes. You will not drown. You may even feel lighter afterward.", dayNumber: 10 },
  { id: 311, type: 7, category: "growth", title: "Deep Focus Practice", prompt: "At your integration point, you access the Five\'s gift of deep, sustained focus. Today, choose one subject and study it for a full hour without switching topics, checking your phone, or multitasking. Let depth replace breadth.", dayNumber: 11 },
  { id: 312, type: 7, category: "growth", title: "The Single-Task Day", prompt: "Sevens habitually multitask. Today, do one thing at a time. When you eat, only eat. When you work, only work. When you listen, only listen. The Five\'s gift is the ability to be fully absorbed in a single pursuit. Practice this radical simplicity.", dayNumber: 12 },
  { id: 313, type: 7, category: "growth", title: "Sitting With Discomfort", prompt: "When discomfort arises today — boredom, restlessness, a difficult emotion — do not move away from it. Sit with it for five minutes. The Five integration teaches that discomfort is not a signal to flee; it is often a doorway to insight.", dayNumber: 13 },
  { id: 314, type: 7, category: "growth", title: "Less Is More", prompt: "Today, consciously consume less: fewer inputs, fewer plans, fewer conversations, fewer snacks, fewer screens. Notice what emerges in the space that opens up. The Five knows that emptiness is not deprivation — it is room for depth.", dayNumber: 14 },
  { id: 315, type: 7, category: "growth", title: "The Solitude Experiment", prompt: "Spend an evening alone — truly alone, with no social media, no calls, no plans. The Five thrives in solitude. For a Seven, this may feel like punishment, but it is actually an invitation to discover the richness of your own inner world.", dayNumber: 15 },
  { id: 316, type: 7, category: "growth", title: "Finishing Before Starting", prompt: "Before beginning anything new today — a project, a book, a conversation topic — finish one thing you have already started. The Five\'s integration teaches completion. Let the satisfaction of finishing replace the excitement of starting.", dayNumber: 16 },
  { id: 317, type: 7, category: "growth", title: "The Depth Journal", prompt: "Choose one experience from today and write about it in detail — not a summary, but a deep, nuanced exploration. What did you see, feel, think, notice? The Five\'s gift is the capacity to extract profound meaning from a single experience.", dayNumber: 17 },
  { id: 318, type: 7, category: "growth", title: "Expertise Over Dabbling", prompt: "Sevens know a little about everything; Fives know a lot about something. Today, identify one area of genuine expertise you want to develop and commit to it. Read one substantial article or chapter. Build depth rather than collecting breadth.", dayNumber: 18 },
  { id: 319, type: 7, category: "growth", title: "The Observation Practice", prompt: "Sit in a public place for twenty minutes and observe. Do not interact, do not plan, do not entertain yourself. Simply watch. The Five\'s gift is careful, patient observation. Let the world reveal its details to you rather than chasing stimulation.", dayNumber: 19 },
  { id: 320, type: 7, category: "growth", title: "The \"No\" Practice", prompt: "Say no to one invitation, one opportunity, or one impulse today. Not because it is bad, but because your plate is full and your attention is better invested in what you already have. The Five integration teaches the power of selective engagement.", dayNumber: 20 },
  { id: 321, type: 7, category: "mindfulness", title: "The Stillness Challenge", prompt: "Sevens are in constant mental motion. Today, sit in stillness for ten minutes. When your mind generates a plan, an idea, or an exciting thought, notice it and let it pass. Do not follow it. Practice being the still center around which thoughts orbit.", dayNumber: 21 },
  { id: 322, type: 7, category: "mindfulness", title: "Grounding Through the Body", prompt: "When restlessness hits, drop your attention from your racing mind into your body. Feel the weight of your legs. The solidity of your bones. The rhythm of your breathing. Your body exists only in the present — it is the antidote to the mind\'s constant future-tripping.", dayNumber: 22 },
  { id: 323, type: 7, category: "mindfulness", title: "The Sobriety Breath", prompt: "Your virtue is sobriety — not abstinence, but clear-eyed presence. Practice this: with each inhale, silently say \"here.\" With each exhale, \"now.\" Five minutes of this practice trains your attention to land in the one moment that is actually real.", dayNumber: 23 },
  { id: 324, type: 7, category: "mindfulness", title: "The Restlessness Investigation", prompt: "When restlessness arises today, do not obey it. Instead, get curious: where is it in your body? What does it feel like — buzzy, tight, itchy? What is underneath it? Often, Seven restlessness is a cover for anxiety or sadness. Let yourself find out.", dayNumber: 24 },
  { id: 325, type: 7, category: "mindfulness", title: "Slow Eating Practice", prompt: "Eat one meal today at half your normal speed. Put your fork down between bites. Taste each flavor. Notice each texture. Sevens tend to rush through experiences, already anticipating the next one. Let this meal be complete in itself.", dayNumber: 25 },
  { id: 326, type: 7, category: "mindfulness", title: "The Five-Senses Anchor", prompt: "When your mind begins racing through plans and possibilities, use this grounding technique: name one thing you can see, hear, smell, taste, and touch right now. This pulls you from the exciting movie in your head back to the rich reality of the present.", dayNumber: 26 },
  { id: 327, type: 7, category: "mindfulness", title: "Breath Counting for the Scattered Mind", prompt: "Sit quietly and count your breaths from one to ten. If you lose count — and you will — start over. This is not a failure; it is the practice. Each return to counting is a repetition of choosing focus over distraction. Aim for three complete cycles.", dayNumber: 27 },
  { id: 328, type: 7, category: "mindfulness", title: "Walking Slowly", prompt: "Take a walk at half your normal pace. Let yourself be passed by others. Feel each footstep. Sevens walk fast because they are always heading toward the next thing. Today, practice walking as though the journey is the destination.", dayNumber: 28 },
  { id: 329, type: 7, category: "mindfulness", title: "The Contentment Scan", prompt: "Instead of scanning for what is missing or what could be better, scan for what is already satisfying. Right now, what in your immediate environment is actually good? The temperature, the light, the comfort of your chair. Practice arriving in contentment rather than perpetually departing toward more.", dayNumber: 29 },
  { id: 330, type: 7, category: "mindfulness", title: "Evening Stillness Ritual", prompt: "Before bed, sit in darkness for five minutes with no stimulation. Let the day\'s experiences settle. Do not plan tomorrow. Do not replay highlights. Just be in the quiet. For a Seven, this practice is the most challenging — and the most transformative.", dayNumber: 30 },
  { id: 331, type: 7, category: "relationship", title: "The Full Attention Gift", prompt: "In your next conversation, give the other person your complete, undivided attention. Do not plan your response while they speak. Do not redirect to a related story. Do not check your phone. Pure, sustained attention is one of the rarest gifts a Seven can offer.", dayNumber: 31 },
  { id: 332, type: 7, category: "relationship", title: "Staying When It Gets Heavy", prompt: "When a conversation turns emotional or heavy, Sevens instinctively lighten the mood. Today, resist that impulse. When someone shares pain, sit with them in it. Say: \"I am here. This is hard.\" Let silence replace humor.", dayNumber: 32 },
  { id: 333, type: 7, category: "relationship", title: "Following Through", prompt: "Identify one promise or commitment you made to someone and have not fulfilled. Today, follow through on it. For Sevens, enthusiasm at the point of commitment is easy; follow-through is the practice of real love.", dayNumber: 33 },
  { id: 334, type: 7, category: "relationship", title: "Having the Boring Conversation", prompt: "Relationships require conversations about logistics, feelings, and problems that are not exciting. Today, initiate or willingly engage in one of these \"boring\" conversations with full presence. The maintenance of love is as important as its fireworks.", dayNumber: 34 },
  { id: 335, type: 7, category: "relationship", title: "Apologizing for Absence", prompt: "Think of someone who has needed your sustained attention and did not get it because you were distracted by the next shiny thing. Today, acknowledge it: \"I know I have not been fully present. I am sorry, and I want to do better.\"", dayNumber: 35 },
  { id: 336, type: 7, category: "relationship", title: "Depth Over Entertainment", prompt: "In your next social interaction, ask a deep question rather than telling an entertaining story. \"What are you struggling with?\" \"What matters most to you right now?\" Let the conversation go below the surface, even if it feels less fun.", dayNumber: 36 },
  { id: 337, type: 7, category: "relationship", title: "The Commitment Conversation", prompt: "If there is a relationship where you have been keeping your options open — romantically, professionally, or in friendship — today have an honest conversation about your level of commitment. Let the other person know where you stand.", dayNumber: 37 },
  { id: 338, type: 7, category: "relationship", title: "Receiving Feedback Without Deflecting", prompt: "When someone gives you critical feedback today, listen fully without deflecting with humor, reframing it as positive, or changing the subject. Say: \"Thank you for telling me that. I want to sit with it.\" Let difficult input land.", dayNumber: 38 },
  { id: 339, type: 7, category: "relationship", title: "Being Bored Together", prompt: "Spend time with someone you care about doing nothing special. No restaurant, no adventure, no plan. Just coexist. Let the relationship exist without stimulation. If it survives boredom, it is real.", dayNumber: 39 },
  { id: 340, type: 7, category: "relationship", title: "Sharing Your Fear", prompt: "Sevens project fearlessness, but deep down there is often profound anxiety about suffering and limitation. Today, share a genuine fear with someone close: \"I am afraid of ___.\" Let someone see the vulnerability beneath the enthusiasm.", dayNumber: 40 },
  { id: 341, type: 7, category: "affirmation", title: "\"This moment is enough.\"", prompt: "Repeat this when the pull toward the next experience begins. You do not need more. This moment — with its ordinary texture, its quiet aliveness — is complete. Let it be enough.", dayNumber: 41 },
  { id: 342, type: 7, category: "affirmation", title: "\"I can feel pain and survive.\"", prompt: "This is the Seven\'s core healing. The avoidance of pain has been your organizing principle, but you are stronger than you think. Pain is temporary. Running from it is exhausting. Today, let this mantra give you permission to feel what you have been fleeing.", dayNumber: 42 },
  { id: 343, type: 7, category: "affirmation", title: "\"Depth is more satisfying than breadth.\"", prompt: "Use this when you are tempted to add another commitment, another plan, another option. One deep well provides more water than a hundred shallow puddles. Let this mantra redirect your gluttony toward depth.", dayNumber: 43 },
  { id: 344, type: 7, category: "affirmation", title: "\"Sobriety is not deprivation — it is clarity.\"", prompt: "Your virtue is sobriety: the clear-eyed ability to see reality without the haze of fantasy or anticipation. Say this when the impulse to escape into excitement arises. Clarity is its own reward.", dayNumber: 44 },
  { id: 345, type: 7, category: "affirmation", title: "\"I do not need to outrun my feelings.\"", prompt: "When restlessness surges, say this. Your feelings are not predators chasing you. They are parts of yourself asking to be met. You can slow down. You can turn around. You can face what is there.", dayNumber: 45 },
  { id: 346, type: 7, category: "affirmation", title: "\"Less options, more presence.\"", prompt: "Use this as a decision-making filter today. When tempted to keep all possibilities open, choose one and close the others. Presence requires commitment, and commitment requires closing doors. The ones that remain open are richer for it.", dayNumber: 46 },
  { id: 347, type: 7, category: "affirmation", title: "\"Gratitude is the antidote to gluttony.\"", prompt: "When wanting surges — more, better, different — practice gratitude for what already exists. Name three things you have right now that past-you would have been thrilled by. Let gratitude fill the space that wanting keeps empty.", dayNumber: 47 },
  { id: 348, type: 7, category: "affirmation", title: "\"I am here. I choose to stay.\"", prompt: "Say this when the urge to leave — a conversation, a commitment, a difficult feeling — arises. You do not have to flee. You can stay. And in staying, you may discover that what you were running from was actually what you needed most.", dayNumber: 48 },
  { id: 349, type: 7, category: "affirmation", title: "\"My pain has something to teach me.\"", prompt: "Use this to transform your relationship with suffering. Pain is not meaningless. It is not a punishment. It carries wisdom that joy cannot access. Today, let this mantra make you curious about your pain rather than afraid of it.", dayNumber: 49 },
  { id: 350, type: 7, category: "affirmation", title: "\"Freedom is found in commitment, not in options.\"", prompt: "This is the Seven\'s paradox: the endless pursuit of freedom through keeping options open actually creates a prison of restlessness. True freedom comes from choosing deeply. Let this mantra redefine what freedom means to you.", dayNumber: 50 },
  { id: 351, type: 8, category: "shadow", title: "The Vulnerability Inventory", prompt: "Write down three things that make you feel vulnerable — not physically, but emotionally. A rejection, a need for approval, a fear of being seen as weak. For each one, journal: how does your refusal to show this vulnerability affect your relationships? What would it cost to let someone see it?", dayNumber: 1 },
  { id: 352, type: 8, category: "shadow", title: "Anger as Armor", prompt: "Eights lead with anger because it feels powerful and safe. But underneath anger, there is almost always a softer emotion: hurt, fear, sadness, or grief. Today, when anger arises, pause and ask: \"What is the feeling underneath this anger?\" Let yourself find the tenderness beneath the fire.", dayNumber: 2 },
  { id: 353, type: 8, category: "shadow", title: "The Control Audit", prompt: "List five areas of your life where you exert strong control — over people, environments, outcomes, or narratives. For each one, ask: \"What am I afraid would happen if I let go?\" Control is the Eight\'s primary defense. Understanding what it defends is the beginning of freedom.", dayNumber: 3 },
  { id: 354, type: 8, category: "shadow", title: "Intimidation Awareness", prompt: "Eights often do not realize when they are intimidating others. Today, pay attention to how people respond to you: do they become quiet, agreeable, or careful with their words? If so, your intensity may be creating a dynamic where no one tells you the truth. Journal about what honest feedback might sound like.", dayNumber: 4 },
  { id: 355, type: 8, category: "shadow", title: "The Betrayal Wound", prompt: "Eights often became tough because someone they trusted betrayed, failed, or hurt them. Journal about your original betrayal wound — the experience that taught you the world was not safe and that you needed to be strong. What would it mean to grieve that experience rather than armor against its recurrence?", dayNumber: 5 },
  { id: 356, type: 8, category: "shadow", title: "Excess as Avoidance", prompt: "Your passion is lust — not just sexual, but a craving for intensity, excess, and impact. Today, notice where you do things excessively: eating, drinking, working, arguing, exercising. Ask: \"What would I feel if I stopped right now?\" The excess is often filling a void you have not examined.", dayNumber: 6 },
  { id: 357, type: 8, category: "shadow", title: "The Softness You Despise", prompt: "Eights often despise in others what they have disowned in themselves — weakness, neediness, indecisiveness. Today, when you feel contempt toward someone\'s vulnerability, ask: \"Is this a part of myself I have rejected?\" The thing you judge most harshly in others is often your own exiled quality.", dayNumber: 7 },
  { id: 358, type: 8, category: "shadow", title: "Justice or Vengeance?", prompt: "Your fixation is vengeance — a desire to right wrongs and punish those who have caused harm. Today, examine one situation where your pursuit of \"justice\" may have actually been about revenge, control, or reasserting dominance. Where is the line between justice and vengeance in your life?", dayNumber: 8 },
  { id: 359, type: 8, category: "shadow", title: "The Cost of Being Strong", prompt: "Journal about what your strength has cost you. Missed tenderness. Alienated friends. Unprocessed grief. Relationships where you were respected but not truly known. Your strength is real and valuable, but it has a price. Are you willing to acknowledge what you have paid?", dayNumber: 9 },
  { id: 360, type: 8, category: "shadow", title: "Admitting Hurt", prompt: "Today, find one person you trust and say the words: \"That hurt me.\" Not \"that made me angry\" — anger is where Eights go to avoid hurt. The specific phrase \"that hurt me\" admits a vulnerability that anger conceals. Notice how the admission feels — dangerous, perhaps, but also freeing.", dayNumber: 10 },
  { id: 361, type: 8, category: "growth", title: "The Tender Gesture", prompt: "At your integration point, you access the Two\'s gift of warmth and tenderness. Today, perform one genuinely tender action: a heartfelt note, a gentle touch, a quiet act of service that asks nothing in return. Let softness be your strength.", dayNumber: 11 },
  { id: 362, type: 8, category: "growth", title: "Asking for Help", prompt: "Eights would rather break than bend, rather struggle than ask for help. Today, ask someone for help with something you could technically do alone. \"Could you help me with this?\" is one of the bravest sentences an Eight can speak.", dayNumber: 12 },
  { id: 363, type: 8, category: "growth", title: "Listening Without Fixing", prompt: "The Two\'s gift is the ability to hold space for others\' emotions without taking action. Today, when someone shares a problem, listen without solving it. Do not strategize, advise, or take charge. Simply say: \"I hear you. That sounds hard.\"", dayNumber: 13 },
  { id: 364, type: 8, category: "growth", title: "Nurturing Yourself", prompt: "Eights are better at protecting others than nurturing themselves. Today, do something genuinely nurturing for yourself — not intense or indulgent, but gentle. A warm bath, a quiet cup of tea, a slow morning. Let yourself be cared for, even if the caretaker is you.", dayNumber: 14 },
  { id: 365, type: 8, category: "growth", title: "The Compliment Practice", prompt: "Eights express love through protection and challenge more than through affirmation. Today, give three genuine, specific compliments to people in your life. \"I appreciate your kindness.\" \"You handled that beautifully.\" Let warmth flow without the need for it to prove anything.", dayNumber: 15 },
  { id: 366, type: 8, category: "growth", title: "Service Without Control", prompt: "Volunteer to help someone today in a way that gives them agency. Instead of taking over, ask: \"What would be most helpful to you?\" and do what they request. The Two integration teaches that service is about the other person\'s needs, not your own power.", dayNumber: 16 },
  { id: 367, type: 8, category: "growth", title: "Emotional Check-In", prompt: "Three times today, ask someone: \"How are you — really?\" And then wait for the real answer. Not a surface exchange, but a genuine inquiry into their inner state. The Two\'s gift is emotional attentiveness. Practice it.", dayNumber: 17 },
  { id: 368, type: 8, category: "growth", title: "Receiving Tenderness", prompt: "When someone offers you tenderness — a kind word, a gentle touch, a moment of care — receive it without deflecting, joking, or stiffening. Let yourself be softened by someone else\'s love. Your armor does not need to be on every moment.", dayNumber: 18 },
  { id: 369, type: 8, category: "growth", title: "The Empathy Practice", prompt: "Choose one person you are in conflict with and spend five minutes genuinely imagining their experience. Not to strategize against them, but to understand them. What are they afraid of? What do they need? The Two\'s gift is the ability to enter another\'s world.", dayNumber: 19 },
  { id: 370, type: 8, category: "growth", title: "Expressing Love Verbally", prompt: "Eights often show love through action but struggle to say the words. Today, tell someone \"I love you\" or \"You are important to me\" — not as a casual sign-off, but as a deliberate, eyes-meeting statement. Let the words carry their full weight.", dayNumber: 20 },
  { id: 371, type: 8, category: "mindfulness", title: "The Intensity Dimmer", prompt: "Eights default to high intensity. Today, practice deliberately lowering your intensity in one interaction. Speak more softly. Move more slowly. Take up slightly less space. Notice what happens when you turn the volume down — you may find that people actually draw closer.", dayNumber: 21 },
  { id: 372, type: 8, category: "mindfulness", title: "Belly Breathing for Grounding", prompt: "As a gut-center type, your power lives in your belly. Spend five minutes breathing deeply into your abdomen. With each exhale, release the need to control anything. Let the breath soften the constant vigilance in your gut.", dayNumber: 22 },
  { id: 373, type: 8, category: "mindfulness", title: "The Anger Pause", prompt: "Before acting on anger today, pause for three full breaths. In those breaths, feel the anger as pure energy in your body — the heat, the tension, the surge. Then ask: \"What does this situation actually need from me right now?\" Let wisdom, not reactivity, guide your response.", dayNumber: 23 },
  { id: 374, type: 8, category: "mindfulness", title: "Softening the Body", prompt: "Eights carry tension as armor — tight shoulders, clenched fists, a forward-leaning stance. Three times today, consciously soften: drop your shoulders, unclench your hands, lean back. Let your body remember what it feels like to not be bracing for battle.", dayNumber: 24 },
  { id: 375, type: 8, category: "mindfulness", title: "The Innocence Meditation", prompt: "Your virtue is innocence — the capacity to meet the world with openness, as you did before you learned to defend yourself. Close your eyes and remember a moment from childhood when you felt safe and open. Breathe into that feeling. It is still accessible to you.", dayNumber: 25 },
  { id: 376, type: 8, category: "mindfulness", title: "Sensation Without Story", prompt: "When a strong emotion arises today, feel it as a physical sensation without the story attached. Not \"I am angry because they disrespected me\" but \"I feel heat and tightness in my chest.\" The sensation is real. The story may or may not be. Practice separating them.", dayNumber: 26 },
  { id: 377, type: 8, category: "mindfulness", title: "Walking Gently", prompt: "Take a 15-minute walk, but instead of your usual powerful stride, walk gently. Step lightly. Feel each footfall as though you were walking on something precious. Let your body practice gentleness as a deliberate choice, not a weakness.", dayNumber: 27 },
  { id: 378, type: 8, category: "mindfulness", title: "The Release Practice", prompt: "Lie on your back and systematically tense every muscle group for five seconds, then release. With each release, exhale and say \"let go.\" Eights hold on — to control, to power, to intensity. This practice teaches your body the physical skill of release.", dayNumber: 28 },
  { id: 379, type: 8, category: "mindfulness", title: "Heart-Opening Stretch", prompt: "Do a chest-opening stretch: stand in a doorway with your arms at your sides pressing against the frame, then lean forward. Feel your chest open. Eights protect their heart with a fortress of muscle and attitude. This stretch physically opens the space you have been guarding.", dayNumber: 29 },
  { id: 380, type: 8, category: "mindfulness", title: "The Power of Stillness", prompt: "Sit completely still for ten minutes. No movement, no fidgeting, no agenda. For an Eight, this is counterintuitive — power usually means action. But there is a deeper power in stillness: the power of being fully present without the need to do, control, or dominate.", dayNumber: 30 },
  { id: 381, type: 8, category: "relationship", title: "Yielding in an Argument", prompt: "The next time you are in a disagreement, practice yielding — not because you are wrong, but because the relationship matters more than the point. Say: \"You may be right\" or \"I want to understand your perspective better.\" Let someone else win and notice that your world does not collapse.", dayNumber: 31 },
  { id: 382, type: 8, category: "relationship", title: "Showing Vulnerability to a Partner", prompt: "Tell someone close to you about a fear or insecurity you normally hide. Not as a test of their strength, but as a gift of trust. \"I am afraid of ___\" or \"Sometimes I feel ___.\" Vulnerability deepens intimacy in ways that strength alone cannot.", dayNumber: 32 },
  { id: 383, type: 8, category: "relationship", title: "Checking Your Impact", prompt: "Ask someone you trust: \"Am I too much sometimes? Do I ever make you feel bulldozed or unheard?\" Listen to their answer without defending yourself. Eights often do not see their own impact because people are too intimidated to tell them the truth.", dayNumber: 33 },
  { id: 384, type: 8, category: "relationship", title: "Equal Power Dynamics", prompt: "Eights gravitate toward control in relationships. Today, consciously create space for equal power: let your partner choose the restaurant, let your colleague lead the meeting, let your friend set the plan. Practice partnership over dominance.", dayNumber: 34 },
  { id: 385, type: 8, category: "relationship", title: "The Apology Without Justification", prompt: "When you have overstepped today — and you may — offer a clean apology: \"I was too aggressive. I am sorry.\" Not \"I am sorry, but you provoked me.\" The justification negates the apology. Let your apology stand alone.", dayNumber: 35 },
  { id: 386, type: 8, category: "relationship", title: "Patience With Weakness", prompt: "When someone moves slowly, hesitates, or shows indecision, practice patience instead of contempt. Remember that not everyone leads with strength, and that tenderness is not weakness. Say to yourself: \"Their pace is valid. I do not need to push.\"", dayNumber: 36 },
  { id: 387, type: 8, category: "relationship", title: "Letting Someone See You Cry", prompt: "If tears come — and Eights work hard to ensure they do not — let someone see them. You do not have to explain. You do not have to recover immediately. Just let the tears fall in the presence of another person. This is among the bravest things an Eight can do.", dayNumber: 37 },
  { id: 388, type: 8, category: "relationship", title: "Trusting Someone Else\'s Competence", prompt: "Delegate something important today and resist the urge to micromanage or take it back. Trust that the other person can handle it. If the result is imperfect, practice accepting it. Not everyone does things the way you would — and that is acceptable.", dayNumber: 38 },
  { id: 389, type: 8, category: "relationship", title: "The Gentle Truth", prompt: "Eights value truth-telling, but the delivery can be brutal. Today, practice telling a truth with gentleness: \"I want to share something with you, and I want to do it kindly.\" The truth does not need to hit like a hammer to be effective.", dayNumber: 39 },
  { id: 390, type: 8, category: "relationship", title: "Asking About Impact", prompt: "After an intense interaction, check in with the other person: \"How did that land for you? Are we okay?\" Eights charge forward and assume others are keeping up. Sometimes they are not. The check-in is an act of care.", dayNumber: 40 },
  { id: 391, type: 8, category: "affirmation", title: "\"Vulnerability is my greatest strength.\"", prompt: "Repeat this when you feel the instinct to armor up. The paradox of the Eight is that true power includes the ability to be soft. Your vulnerability does not weaken you — it completes you.", dayNumber: 41 },
  { id: 392, type: 8, category: "affirmation", title: "\"I do not need to control this moment.\"", prompt: "Use this when the compulsion to take charge arises. Not every situation requires your leadership. Sometimes the most powerful thing you can do is let go and trust the process.", dayNumber: 42 },
  { id: 393, type: 8, category: "affirmation", title: "\"Gentleness is not weakness.\"", prompt: "This is the Eight\'s essential learning. Say it when you are tempted to push harder, speak louder, or dominate a situation. Gentleness requires more strength than force — it is power, refined.", dayNumber: 43 },
  { id: 394, type: 8, category: "affirmation", title: "\"I am safe enough to be soft.\"", prompt: "Eights built their armor in response to a world that was not safe. Today, remind yourself that you have created enough safety to begin removing some of that armor. You are strong enough now to be soft.", dayNumber: 44 },
  { id: 395, type: 8, category: "affirmation", title: "\"My anger serves me — I do not serve my anger.\"", prompt: "Use this when anger threatens to take the wheel. Your anger is a powerful ally, but you are its master, not its servant. Today, choose when and how your anger is expressed.", dayNumber: 45 },
  { id: 396, type: 8, category: "affirmation", title: "\"I can protect others without controlling them.\"", prompt: "Eights blur the line between protection and control. This mantra helps you see the difference. Protection respects the other person\'s autonomy. Control removes it. Today, protect without possessing.", dayNumber: 46 },
  { id: 397, type: 8, category: "affirmation", title: "\"The world is not as dangerous as my body believes.\"", prompt: "Your nervous system was calibrated for a threatening world. But you are no longer the child who needed to fight. Say this when your body tenses for a battle that is not actually happening.", dayNumber: 47 },
  { id: 398, type: 8, category: "affirmation", title: "\"I choose innocence over cynicism today.\"", prompt: "Your virtue is innocence — the ability to see the world with fresh eyes, unclouded by suspicion and self-protection. Today, let this mantra invite you to be open, curious, and trusting, even for a few moments.", dayNumber: 48 },
  { id: 399, type: 8, category: "affirmation", title: "\"Surrender is not defeat.\"", prompt: "For Eights, surrender feels like death. But spiritual surrender — releasing the need to fight, control, and dominate — is actually liberation. Today, surrender one thing: an argument, a grudge, a need to be right.", dayNumber: 49 },
  { id: 400, type: 8, category: "affirmation", title: "\"My tenderness is as real as my power.\"", prompt: "Use this as a closing meditation. Both live in you — the fierce protector and the tender heart. Today, let them exist together. You do not have to choose between strength and softness. You are both.", dayNumber: 50 },
  { id: 401, type: 9, category: "shadow", title: "The Self-Forgetting Inventory", prompt: "When was the last time you prioritized your own desire over someone else\'s preference? Journal about how you habitually erase yourself — agreeing to restaurants you do not want, activities that bore you, plans that drain you. Where did you go?", dayNumber: 1 },
  { id: 402, type: 9, category: "shadow", title: "The Anger You Buried", prompt: "Nines are the anger type that has fallen asleep to their anger. But it has not disappeared — it leaks out as stubbornness, procrastination, passive resistance, and quiet withdrawal. Today, write about what you are actually angry about. Let the anger be direct, raw, and honest.", dayNumber: 2 },
  { id: 403, type: 9, category: "shadow", title: "Numbing Out Awareness", prompt: "Track today how often you numb: scrolling, snacking, bingeing shows, daydreaming, sleeping more than needed. For each instance, ask: \"What am I avoiding right now?\" Numbing is the Nine\'s primary mechanism for avoiding inner turmoil. Name what is underneath.", dayNumber: 3 },
  { id: 404, type: 9, category: "shadow", title: "The Passive Aggression Mirror", prompt: "Nines avoid direct confrontation but express anger through passive means: forgetting tasks, being late, giving the silent treatment, agreeing verbally but not following through. Today, honestly identify one passive-aggressive behavior you have engaged in recently. What would direct expression of that feeling look like?", dayNumber: 4 },
  { id: 405, type: 9, category: "shadow", title: "The Merge Check", prompt: "Nines unconsciously merge with others\' agendas, opinions, and energy. Today, in each significant interaction, pause and ask: \"Is this what I think, or is this what they think? Is this what I want, or is this what keeps the peace?\" Practice detecting where you end and others begin.", dayNumber: 5 },
  { id: 406, type: 9, category: "shadow", title: "The \"It Doesn\'t Matter\" Lie", prompt: "How often do you say \"I do not mind,\" \"whatever you want,\" or \"it does not matter to me\"? Today, when you notice this response arising, pause and check: does it genuinely not matter, or have you simply decided that your preference is not worth the conflict?", dayNumber: 6 },
  { id: 407, type: 9, category: "shadow", title: "Procrastination as Resistance", prompt: "Nine procrastination is not laziness — it is a form of passive resistance against demands, expectations, or inner priorities that feel overwhelming. Today, identify one thing you have been putting off and journal: \"What am I resisting, and why?\"", dayNumber: 7 },
  { id: 408, type: 9, category: "shadow", title: "The Invisible Self", prompt: "Journal about the experience of being overlooked, ignored, or invisible. Is there a part of you that has made peace with being unseen because visibility would require asserting yourself? What would change if you demanded to be seen?", dayNumber: 8 },
  { id: 409, type: 9, category: "shadow", title: "The Comfort Trap", prompt: "Nines prioritize comfort and avoid disruption. Today, identify one way your pursuit of comfort is keeping you stuck — staying in a job, a relationship, or a routine that has outgrown you because change feels disruptive. What is comfort costing you?", dayNumber: 9 },
  { id: 410, type: 9, category: "shadow", title: "Inertia and Your Unlived Life", prompt: "Your passion is sloth, which in the Enneagram does not mean laziness but rather a spiritual inertia — a going to sleep to your own life, priorities, and desires. Journal about the life you would be living if you were fully awake to your own wants. What has inertia prevented you from pursuing?", dayNumber: 10 },
  { id: 411, type: 9, category: "growth", title: "Setting One Goal", prompt: "At your integration point, you access the Three\'s gift of focused ambition. Today, set one specific, measurable goal for yourself — not for someone else, not to keep the peace, but because you want it. Write it down. Put a deadline on it. Let your desire matter.", dayNumber: 11 },
  { id: 412, type: 9, category: "growth", title: "The Self-Advocacy Practice", prompt: "Threes know how to advocate for themselves. Today, advocate for yourself in one situation: ask for the raise, state your preference for dinner, volunteer your opinion in a meeting. Practice the belief that your voice has value.", dayNumber: 12 },
  { id: 413, type: 9, category: "growth", title: "Taking Decisive Action", prompt: "Nines deliberate, defer, and delay. Today, make one decision quickly and act on it immediately. Do not consult others, do not weigh every option, do not wait for the perfect moment. The Three integration teaches that imperfect action beats perpetual hesitation.", dayNumber: 13 },
  { id: 414, type: 9, category: "growth", title: "The Energy Experiment", prompt: "Nines often have low energy because they do not invest in themselves. Today, invest energy in one thing that is solely for you: an exercise class, a creative project, a career move. The Three\'s vitality comes from pursuing personal goals. Borrow that fire.", dayNumber: 14 },
  { id: 415, type: 9, category: "growth", title: "Claiming Space in a Group", prompt: "In your next group interaction, speak up early rather than waiting to see what everyone else thinks. Share your opinion before the group consensus forms. The Three integration helps Nines realize that they have something valuable to contribute.", dayNumber: 15 },
  { id: 416, type: 9, category: "growth", title: "The Accomplishment Journal", prompt: "At day\'s end, write down three things you accomplished today — even small ones. Nines tend to minimize their contributions. Seeing your accomplishments in writing counters the pattern of self-erasure and builds momentum.", dayNumber: 16 },
  { id: 417, type: 9, category: "growth", title: "The \"What Do I Want?\" Practice", prompt: "Five times today, stop and ask yourself: \"What do I want right now?\" Not what is expected, not what others want, not what is easiest — what do you genuinely want? The answer may take time to surface. Wait for it.", dayNumber: 17 },
  { id: 418, type: 9, category: "growth", title: "Dressing With Intention", prompt: "Nines often dress for comfort and blending in. Today, choose an outfit that makes you feel present, visible, and alive. The Three\'s attention to presentation is not vanity — it is self-expression. Let your appearance say \"I am here.\"", dayNumber: 18 },
  { id: 419, type: 9, category: "growth", title: "The Productive Hour", prompt: "Block one hour today for focused, productive work on something that matters to you. Set a timer. Eliminate distractions. Work with the Three\'s purposeful intensity. Afterward, notice how accomplishment feels — it may be more energizing than the comfort you usually choose.", dayNumber: 19 },
  { id: 420, type: 9, category: "growth", title: "Competing Gently", prompt: "Nines avoid competition because it creates conflict. Today, allow yourself to compete in a small way — a game, a friendly challenge, a professional bid. The Three integration teaches that healthy competition is not aggression — it is engagement with life.", dayNumber: 20 },
  { id: 421, type: 9, category: "mindfulness", title: "The Wake-Up Alarm", prompt: "Nines fall asleep to themselves, sometimes literally. Set three alarms today. At each one, stand up, stretch, and ask: \"Am I awake right now? Am I present? Am I doing what matters to me?\" Let these alarms be gentle interruptions to your autopilot.", dayNumber: 21 },
  { id: 422, type: 9, category: "mindfulness", title: "Grounding in Your Body", prompt: "As a gut-center type, your body is your center of intelligence — but Nines often disconnect from it. Today, spend five minutes standing with your feet hip-width apart, feeling your weight on the ground. Clench your fists, then release them. Feel your body as a source of power.", dayNumber: 22 },
  { id: 423, type: 9, category: "mindfulness", title: "The Anger Breath", prompt: "Nines suppress anger until they cannot feel it. Today, practice this breath: inhale sharply through the nose (like a bull snorting), exhale forcefully through the mouth. Repeat ten times. This breath pattern activates the gut center\'s fire. Let it wake up your buried anger.", dayNumber: 23 },
  { id: 424, type: 9, category: "mindfulness", title: "Walking With Purpose", prompt: "Take a 15-minute walk, but instead of your usual meandering pace, walk with purpose: head up, stride firm, eyes forward. Let your body communicate intention and direction. For a Nine, purposeful movement is a somatic antidote to inertia.", dayNumber: 24 },
  { id: 425, type: 9, category: "mindfulness", title: "The Boundary Body Practice", prompt: "Stand in the center of a room. Extend your arms and slowly turn in a circle, imagining you are defining your personal space. Say aloud: \"This is my space. My needs live here. My voice lives here.\" Let your body claim the territory your mind surrenders.", dayNumber: 25 },
  { id: 426, type: 9, category: "mindfulness", title: "Right Action Meditation", prompt: "Your virtue is right action — doing what is needed in the moment rather than what is easiest. Sit quietly and ask: \"What is the right action for me today?\" Not the comfortable action, not the conflict-free action, but the one that serves your growth. Then do it.", dayNumber: 26 },
  { id: 427, type: 9, category: "mindfulness", title: "Noticing Numbness", prompt: "When you feel numb or foggy, do not push past it — investigate it. Sit with the numbness and ask: \"What am I not letting myself feel right now?\" Often, beneath the Nine\'s fog is a clear signal — anger, desire, grief — that has been muted by the body\'s self-protective dimmer switch.", dayNumber: 27 },
  { id: 428, type: 9, category: "mindfulness", title: "Cold Water Wake-Up", prompt: "Splash cold water on your face first thing in the morning. The shock interrupts the Nine\'s tendency to drift into the day on autopilot. Let the cold be a declaration: \"I am here. I am awake. This day is mine.\"", dayNumber: 28 },
  { id: 429, type: 9, category: "mindfulness", title: "The Power Stance", prompt: "Stand in a wide, grounded stance with your hands on your hips for two minutes. Research aside, the physical experience of taking up space and standing in power can shift a Nine\'s energy from passive to engaged. Feel your body\'s strength.", dayNumber: 29 },
  { id: 430, type: 9, category: "mindfulness", title: "Eating With Attention", prompt: "Nines often eat mindlessly — as comfort, as numbing, as background to other activities. Today, eat one meal with full attention. Notice flavor, texture, satiation. When you eat consciously, you are practicing being present in your body rather than floating above it.", dayNumber: 30 },
  { id: 431, type: 9, category: "relationship", title: "Stating Your Preference", prompt: "Today, when someone asks \"What do you want to do?\" answer with an actual preference. Not \"I do not care\" or \"whatever you want.\" A real answer: \"I would like to ___.\" The world will not end. The relationship will not shatter. Your preference matters.", dayNumber: 31 },
  { id: 432, type: 9, category: "relationship", title: "The Direct Conversation", prompt: "Identify one issue you have been avoiding in a relationship. Today, bring it up directly. Not aggressively — just honestly. \"I need to talk about something that has been on my mind.\" The conflict you fear is almost always less painful than the avoidance that precedes it.", dayNumber: 32 },
  { id: 433, type: 9, category: "relationship", title: "Saying \"I Disagree\"", prompt: "Find one moment today to express disagreement — not as an attack, but as a statement of your separate selfhood. \"I see it differently\" or \"I actually disagree.\" For a Nine, disagreement is one of the most self-affirming acts possible.", dayNumber: 33 },
  { id: 434, type: 9, category: "relationship", title: "Showing Up Fully", prompt: "In your next significant conversation, be fully present — not nodding along while mentally drifting. Lean in. Ask questions. Offer your perspective. Let the other person experience you as engaged and alive rather than pleasant and absent.", dayNumber: 34 },
  { id: 435, type: 9, category: "relationship", title: "Withdrawing the Auto-Yes", prompt: "Today, before saying yes to any request, pause for five seconds. In that pause, check: \"Do I actually want to do this, or am I agreeing to avoid friction?\" If you do not want to, say: \"Let me think about that.\" Buy yourself the time to find your real answer.", dayNumber: 35 },
  { id: 436, type: 9, category: "relationship", title: "The Anger Expression", prompt: "Express a small anger to someone today. Not rage — just honest displeasure. \"I did not like when that happened.\" \"That bothered me.\" For Nines, expressing even mild displeasure can feel like dropping a bomb. Practice and see: the explosion does not come.", dayNumber: 36 },
  { id: 437, type: 9, category: "relationship", title: "Taking Up Relational Space", prompt: "In your next group interaction, notice if you are minimizing yourself — sitting at the edge, staying quiet, deferring. Today, move to the center. Speak early. Hold the floor for an extra beat. Let your presence be felt, not just your agreeableness.", dayNumber: 37 },
  { id: 438, type: 9, category: "relationship", title: "Asking for What You Need", prompt: "Choose one relationship and make a specific request: \"I need more quality time.\" \"I need you to listen without fixing.\" \"I need space this weekend.\" Nines rarely make requests because they have lost touch with what they need. The request itself is the practice of self-recovery.", dayNumber: 38 },
  { id: 439, type: 9, category: "relationship", title: "The Uncomfortable Honesty", prompt: "Tell someone an honest thing you have been withholding — a frustration, a boundary, a desire. Preface it with: \"This is hard for me to say, but it is important.\" Your honesty is a gift to the relationship, even when it disturbs the peace.", dayNumber: 39 },
  { id: 440, type: 9, category: "relationship", title: "Being Important to Yourself", prompt: "Nines make everyone else important and forget to include themselves. Today, treat yourself as you would treat your most valued friend: keep your commitments to yourself, respect your time, honor your preferences. Practice being your own priority.", dayNumber: 40 },
  { id: 441, type: 9, category: "affirmation", title: "\"I matter. My voice matters. My presence matters.\"", prompt: "Repeat this when you feel yourself fading into the background. You are not here to be wallpaper. You are here to participate, contribute, and be seen. Say this with your feet firmly on the ground.", dayNumber: 41 },
  { id: 442, type: 9, category: "affirmation", title: "\"I am allowed to want things.\"", prompt: "Nines often feel that having desires creates conflict. This mantra gives you permission to want — a career, a relationship, a life that reflects your true self. Your desires are not inconveniences. They are the blueprints of your unlived life.", dayNumber: 42 },
  { id: 443, type: 9, category: "affirmation", title: "\"Conflict does not mean the end of love.\"", prompt: "This is the Nine\'s essential healing. Say this when you avoid a necessary confrontation. People can disagree, be angry, even argue — and still love each other. Conflict is not destruction. It is often the doorway to deeper connection.", dayNumber: 43 },
  { id: 444, type: 9, category: "affirmation", title: "\"My peace must include me.\"", prompt: "Nines create peace for everyone else while forgetting to include themselves. Today, let this mantra remind you that peace at the cost of self-erasure is not true peace — it is surrender. Real peace includes your needs, your voice, and your presence.", dayNumber: 44 },
  { id: 445, type: 9, category: "affirmation", title: "\"I choose action over comfort today.\"", prompt: "Use this as a morning intention. Comfort is the Nine\'s default, but growth lives outside the comfort zone. Today, choose one action that is uncomfortable but aligned with what you truly want. Right action is your virtue.", dayNumber: 45 },
  { id: 446, type: 9, category: "affirmation", title: "\"I am awake to my own life.\"", prompt: "Say this when you feel the fog of inertia descending — the urge to coast, to go along, to fall asleep to your own existence. You have one life. This mantra is a gentle alarm clock reminding you to live it on purpose.", dayNumber: 46 },
  { id: 447, type: 9, category: "affirmation", title: "\"My anger is welcome here.\"", prompt: "Nines exile their anger because it threatens peace. But anger is energy, boundary, and self-assertion. Today, when anger stirs, welcome it: \"Hello, anger. What are you trying to protect? What do you need me to do?\"", dayNumber: 47 },
  { id: 448, type: 9, category: "affirmation", title: "\"I do not need to disappear to keep the peace.\"", prompt: "When you feel the instinct to shrink, merge, or become invisible in order to avoid tension, say this. You can be present and still be peaceful. Your presence is not the problem — it is the gift.", dayNumber: 48 },
  { id: 449, type: 9, category: "affirmation", title: "\"I am the main character of my own life.\"", prompt: "Nines tend to be supporting characters in everyone else\'s story. This mantra reclaims the protagonist role. Your story is happening now. Your choices shape it. Step into the center of your own narrative.", dayNumber: 49 },
  { id: 450, type: 9, category: "affirmation", title: "\"Today I choose to show up — fully, visibly, unapologetically.\"", prompt: "Use this as a closing commitment. Not showing up halfway, not showing up for others while hiding yourself, but showing up as the full, opinionated, desiring, alive person you are. The world needs your presence, not just your pleasantness.", dayNumber: 50 },
];
